1	//! Agent Nervous System daemon entry point.
2	//!
3	//! Starts two servers:
4	//! - gRPC server on loopback:50051 (internal Python/TS clients)
5	//! - Gateway on loopback:50052 (external AI agents — MCP, REST, WS)
6	//!
7	//! Both run concurrently. Chromium instances are cleaned up on exit
8	//! via RAII drop guards. Ctrl+C triggers graceful shutdown.
9	
10	use std::net::{IpAddr, Ipv4Addr, SocketAddr};
11	use std::path::PathBuf;
12	
13	use ans_ipc::IpcServer;
14	use clap::Parser;
15	use tracing_subscriber::EnvFilter;
16	
17	#[derive(Parser)]
18	#[command(name = "ans-daemon", version, about = "Agent Nervous System daemon")]
19	struct Cli {
20	    /// gRPC port to bind on loopback
21	    #[arg(long, default_value = "50051")]
22	    grpc_port: u16,
23	
24	    /// Gateway port to bind on loopback
25	    #[arg(long, default_value = "50052")]
26	    gateway_port: u16,
27	
28	    /// Path to ans.toml configuration file
29	    #[arg(long, default_value = "ans.toml")]
30	    config: PathBuf,
31	}
32	
33	#[tokio::main]
34	async fn main() {
35	    if let Err(e) = color_eyre::install() {
36	        eprintln!("Failed to install color-eyre panic handler: {e}");
37	        std::process::exit(1);
38	    }
39	
40	    let cli = Cli::parse();
41	
42	    tracing_subscriber::fmt()
43	        .with_env_filter(
44	            EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("ans=debug,info")),
45	        )
46	        .init();
47	
48	    tracing::info!(version = env!("CARGO_PKG_VERSION"), "ans-daemon starting");
49	
50	    if let Some(cfg) = load_config(&cli.config) {
51	        tracing::info!(?cfg, "Config loaded");
52	    } else {
53	        tracing::info!("No config file found, using defaults");
54	    }
55	
56	    // ── Start gRPC server in background ──────────────────────────────
57	    let server = IpcServer::new();
58	    let grpc_addr = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), cli.grpc_port);
59	
60	    let grpc_handle = tokio::spawn(async move {
61	        if let Err(e) = server.serve(grpc_addr).await {
62	            tracing::error!(%e, "gRPC server exited with error");
63	        }
64	    });
65	
66	    // Give the gRPC server a moment to bind before starting the gateway
67	    tokio::time::sleep(std::time::Duration::from_millis(300)).await;
68	
69	    // ── Start gateway ────────────────────────────────────────────────
70	    let gw_addr = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), cli.gateway_port);
71	
72	    let gw_handle = match ans_gateway::Gateway::init().await {
73	        Ok(gateway) => {
74	            tracing::info!("Gateway starting on {}", gw_addr);
75	            tokio::spawn(async move {
76	                if let Err(e) = gateway.serve(gw_addr).await {
77	                    tracing::error!(%e, "Gateway exited with error");
78	                }
79	            })
80	        }
81	        Err(e) => {
82	            tracing::warn!(%e, "Gateway failed to initialize — running gRPC-only");
83	            // Still wait for gRPC server
84	            let _ = grpc_handle.await;
85	            return;
86	        }
87	    };
88	
89	    // ── Wait for shutdown ────────────────────────────────────────────
90	    tokio::select! {
91	        _ = tokio::signal::ctrl_c() => {
92	            tracing::info!("Shutdown signal received");
93	        }
94	        _ = grpc_handle => {
95	            tracing::warn!("gRPC server exited unexpectedly");
96	        }
97	        _ = gw_handle => {
98	            tracing::warn!("Gateway exited unexpectedly");
99	        }
100	    }
101	
102	    tracing::info!("ans-daemon shut down cleanly");
103	}
104	
105	fn load_config(path: &PathBuf) -> Option<toml::Value> {
106	    let content = std::fs::read_to_string(path).ok()?;
107	    toml::from_str(&content).ok()
108	}
