190	    async fn handle_tools_call(&self, id: Option<Value>, body: &Value) -> Value {
191	        let params = body.get("params");
192	        let tool_name = match params.and_then(|p| p.get("name")).and_then(|n| n.as_str()) {
193	            Some(name) => name,
194	            None => return json_rpc_error(id, -32602, "Missing params.name"),
195	        };
196	
197	        let args = params
198	            .and_then(|p| p.get("arguments"))
199	            .cloned()
200	            .unwrap_or_else(|| json!({}));
201	
202	        let result = match tool_name {
203	            "create_session" => self.tool_create_session(&args).await,
204	            "navigate" => self.tool_navigate(&args).await,
205	            "click" => self.tool_click(&args).await,
206	            "type_text" => self.tool_type_text(&args).await,
207	            "scroll" => self.tool_scroll(&args).await,
208	            "screenshot" => self.tool_screenshot(&args).await,
209	            "get_dom" => self.tool_get_dom(&args).await,
210	            "execute_action" => self.tool_execute_action(&args).await,
211	            "check_goal" => self.tool_check_goal(&args).await,
212	            "create_goal" => self.tool_create_goal(&args).await,
213	            other => return json_rpc_error(id, -32602, &format!("Unknown tool: {other}")),
214	        };
215	
216	        match result {
217	            Ok(content) => json_rpc_result(
218	                id,
219	                json!({ "content": [{ "type": "text", "text": content }] }),
220	            ),
221	            Err(e) => json_rpc_error(id, -32000, &e),
222	        }
223	    }
