231	    async fn tool_create_session(&self, args: &Value) -> Result<String, String> {
232	        let goal_id = Self::str_arg(args, "goal_id").unwrap_or("");
233	        let start_url = Self::str_arg(args, "start_url").unwrap_or("about:blank");
234	
235	        let mut client = self.client.clone_client();
236	        let req = tonic::Request::new(ans_proto::ans::CreateSessionRequest {
237	            goal_id: goal_id.into(),
238	            start_url: start_url.into(),
239	            headers: std::collections::HashMap::new(),
240	        });
241	
242	        let resp = client
243	            .create_session(req)
244	            .await
245	            .map_err(|e| format!("gRPC error: {e}"))?
246	            .into_inner();
247	
248	        Ok(serde_json::to_string_pretty(&json!({
249	            "session_id": resp.session_id,
250	            "goal_id": resp.goal_id,
251	            "status": resp.status,
252	            "created_at": resp.created_at,
253	        }))
254	        .unwrap_or_else(|e| format!("serialization error: {e}")))
255	    }
