385	    async fn tool_get_dom(&self, args: &Value) -> Result<String, String> {
386	        let session_id = Self::str_arg(args, "session_id").ok_or("session_id required")?;
387	        let mode = Self::str_arg(args, "mode").unwrap_or("input_fields");
388	
389	        let mut client = self.client.clone_client();
390	        let req = tonic::Request::new(ans_proto::ans::DomRequest {
391	            session_id: session_id.into(),
392	            mode: mode.into(),
393	        });
394	
395	        let resp = client
396	            .get_distilled_dom(req)
