1	//! WebSocket server for streaming events to external agents.
2	//!
3	//! Agents connect at `GET /ws` and receive real-time JSON events:
4	//! goal progress updates, eye reports, and alerts.
5	//!
6	//! Upgrade from HTTP to WebSocket, then push events as they happen.
7	
8	use axum::extract::ws::{Message, WebSocket, WebSocketUpgrade};
9	use axum::response::IntoResponse;
10	use futures_util::{SinkExt, StreamExt};
11	use serde_json::json;
12	use tokio::sync::broadcast;
13	
14	use crate::client::InternalClient;
15	
16	/// WebSocket server state.
17	#[derive(Clone)]
18	pub struct WebSocketServer {
19	    #[allow(dead_code)]
20	    client: InternalClient,
21	    /// Local event bus for forwarding to WS clients.
22	    event_tx: broadcast::Sender<String>,
23	}
24	
25	impl WebSocketServer {
26	    pub fn new(client: InternalClient) -> Self {
27	        let (event_tx, _) = broadcast::channel(256);
28	        Self { client, event_tx }
29	    }
30	
31	    /// Subscribe to internal events. Used by the daemon to push events
32	    /// to the WebSocket layer.
33	    pub fn event_sender(&self) -> broadcast::Sender<String> {
34	        self.event_tx.clone()
35	    }
36	
37	    /// Push an event to all connected WebSocket clients.
38	    pub fn push_event(&self, event: &str) {
39	        let _ = self.event_tx.send(event.to_string());
40	    }
41	
42	    /// Handle a WebSocket upgrade request. Called by the axum router.
43	    pub async fn handle_upgrade(&self, ws: WebSocketUpgrade) -> impl IntoResponse {
44	        let event_rx = self.event_tx.subscribe();
45	        ws.on_upgrade(move |socket| handle_socket(socket, event_rx))
46	    }
47	}
48	
49	/// Run the WebSocket event loop.
50	async fn handle_socket(socket: WebSocket, rx: broadcast::Receiver<String>) {
51	    let (mut sender, mut receiver) = socket.split();
52	
53	    // Send a welcome message
54	    let welcome = json!({
55	        "type": "connected",
56	        "message": "Connected to Agent Nervous System gateway",
57	        "version": env!("CARGO_PKG_VERSION")
58	    });
59	    let _ = sender.send(Message::Text(welcome.to_string())).await;
60	
61	    // Spawn event forwarding from broadcast → WebSocket
62	    let mut event_rx = rx;
63	    let send_handle = tokio::spawn(async move {
64	        while let Ok(event) = event_rx.recv().await {
65	            if sender.send(Message::Text(event)).await.is_err() {
66	                break;
67	            }
68	        }
69	    });
70	
71	    // Process incoming messages (keepalive pings)
72	    while let Some(Ok(msg)) = receiver.next().await {
73	        match msg {
74	            Message::Ping(data) => {
75	                // Pong handled automatically by axum
76	                let _ = data;
77	            }
78	            Message::Close(_) => break,
79	            _ => {}
80	        }
81	    }
82	
83	    send_handle.abort();
84	}
