1	//! API key authentication for the Layer 1 gateway.
2	//!
3	//! Loads `api_keys.json` at startup. Each key has scoped permissions:
4	//! read-only, session-create, or full-access. All MCP, REST, and
5	//! WebSocket endpoints validate the `X-API-Key` header through this
6	//! module before any gRPC call is made.
7	
8	use serde::{Deserialize, Serialize};
9	use std::collections::HashMap;
10	use std::path::PathBuf;
11	use std::sync::Arc;
12	
13	/// Permissions scoped to an API key.
14	#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
15	#[serde(rename_all = "lowercase")]
16	pub enum KeyPermission {
17	    ReadOnly,
18	    SessionCreate,
19	    FullAccess,
20	}
21	
22	impl KeyPermission {
23	    /// Returns true if this permission allows creating sessions.
24	    #[must_use] 
25	    pub const fn can_create_session(&self) -> bool {
26	        matches!(
27	            self,
28	            Self::SessionCreate | Self::FullAccess
29	        )
30	    }
31	
32	    /// Returns true if this permission allows mutating state.
33	    #[must_use] 
34	    pub const fn can_write(&self) -> bool {
35	        matches!(
36	            self,
37	            Self::SessionCreate | Self::FullAccess
38	        )
39	    }
40	
41	    /// Returns true if this permission allows reading state.
42	    #[must_use] 
43	    pub const fn can_read(&self) -> bool {
44	        true // all permissions allow reading
45	    }
46	}
47	
48	/// A single API key entry.
49	#[derive(Debug, Clone, Serialize, Deserialize)]
50	pub struct ApiKeyEntry {
51	    pub key: String,
52	    pub name: String,
53	    pub permission: KeyPermission,
54	}
55	
56	/// The API key registry, loaded from disk at startup.
57	#[derive(Debug, Clone, Serialize, Deserialize)]
58	pub struct KeyRegistry {
59	    keys: HashMap<String, ApiKeyEntry>,
60	}
61	
62	impl KeyRegistry {
63	    /// Load keys from a JSON file on disk. Creates a default
64	    /// admin key if the file does not exist.
65	    pub fn load(path: Option<PathBuf>) -> Result<Self, AuthError> {
66	        let path = path.unwrap_or_else(|| {
67	            let home = dirs_next();
68	            home.join(".ans").join("api_keys.json")
69	        });
70	
71	        match std::fs::read_to_string(&path) {
72	            Ok(contents) => {
73	                let registry: Self = serde_json::from_str(&contents)
74	                    .map_err(|e| AuthError::ParseError(e.to_string()))?;
75	                Ok(registry)
76	            }
77	            Err(e) if e.kind() == std::io::ErrorKind::NotFound => {
78	                Err(AuthError::ConfigMissing(path))
79	            }
80	            Err(e) => Err(AuthError::IoError(e)),
81	        }
82	    }
83	
84	    /// Validate an API key and return its entry. Uses constant-time comparison
85	    /// to mitigate timing side-channel attacks.
86	    #[must_use] 
87	    pub fn validate(&self, api_key: &str) -> Option<&ApiKeyEntry> {
88	        if api_key.is_empty() {
89	            return None;
90	        }
91	        self.keys
92	            .values()
93	            .find(|entry| constant_time_eq(api_key.as_bytes(), entry.key.as_bytes()))
94	    }
95	}
96	
97	/// Cached in an Arc so all request handlers share the same registry.
98	pub type SharedKeyRegistry = Arc<KeyRegistry>;
99	
100	/// Errors that can occur during authentication.
101	#[derive(Debug, thiserror::Error)]
102	pub enum AuthError {
103	    #[error("missing API key")]
104	    MissingKey,
105	
106	    #[error("invalid API key")]
107	    InvalidKey,
108	
109	    #[error("insufficient permissions: required {required:?}, have {have:?}")]
110	    InsufficientPermissions {
111	        required: KeyPermission,
112	        have: KeyPermission,
113	    },
114	
115	    #[error("api_keys.json not found at {0}")]
116	    ConfigMissing(PathBuf),
117	
118	    #[error("failed to parse api_keys.json: {0}")]
119	    ParseError(String),
120	
121	    #[error("io error: {0}")]
122	    IoError(#[from] std::io::Error),
123	}
124	
125	/// Extract an API key from an HTTP header or query parameter.
126	/// Returns `None` for empty keys.
127	pub fn extract_api_key(headers: &axum::http::HeaderMap, query: Option<&str>) -> Option<String> {
128	    let key = if let Some(value) = headers.get("x-api-key") {
129	        value.to_str().ok().map(String::from)
130	    } else if let Some(value) = headers.get("authorization") {
131	        value.to_str().ok().and_then(|auth| auth.strip_prefix("Bearer ").map(String::from))
132	    } else if let Some(q) = query {
133	        q.split('&')
134	            .find_map(|pair| pair.strip_prefix("api_key=").map(String::from))
135	    } else {
136	        None
137	    };
138	    // Reject empty keys
139	    key.filter(|k| !k.is_empty())
140	}
141	
142	/// Axum extractor that validates API keys.
143	///
144	/// Usage: add `AuthLayer::new(registry)` to your axum router.
