168	/// Tower service that validates the API key before each request.
169	#[derive(Clone)]
170	pub struct AuthMiddleware<S> {
171	    inner: S,
172	    registry: SharedKeyRegistry,
173	}
174	
175	impl<S, B> tower::Service<axum::http::Request<B>> for AuthMiddleware<S>
176	where
177	    S: tower::Service<axum::http::Request<B>, Response = axum::response::Response>
178	        + Clone
179	        + Send
180	        + 'static,
181	    S::Future: Send + 'static,
182	    B: Send + 'static,
183	{
184	    type Response = S::Response;
185	    type Error = S::Error;
186	    type Future = futures_util::future::BoxFuture<'static, Result<Self::Response, Self::Error>>;
187	
188	    fn poll_ready(
189	        &mut self,
190	        cx: &mut std::task::Context<'_>,
191	    ) -> std::task::Poll<Result<(), Self::Error>> {
192	        self.inner.poll_ready(cx)
193	    }
194	
195	    fn call(&mut self, mut req: axum::http::Request<B>) -> Self::Future {
196	        let registry = Arc::clone(&self.registry);
197	        let inner = self.inner.clone();
198	        let mut inner = std::mem::replace(&mut self.inner, inner);
199	
200	        // Extract headers before the request is consumed
201	        let headers = req.headers().clone();
202	        let query = req.uri().query().map(String::from);
203	
204	        Box::pin(async move {
205	            let api_key = extract_api_key(&headers, query.as_deref());
206	            // Look up the entry once for both validation and permission scoping
207	            let entry = api_key.as_ref().and_then(|k| registry.validate(k));
208	            match entry {
209	                Some(entry) => {
210	                    req.extensions_mut().insert(entry.permission.clone());
211	                    inner.call(req).await
212	                }
213	                None if api_key.is_some() => {
214	                    #[allow(clippy::unwrap_used)]
215	                    // SAFETY: Body::from(&str) is infallible — the builder only
216	                    // returns Err when a previously-set body is overwritten.
217	                    let response = axum::response::Response::builder()
218	                        .status(axum::http::StatusCode::UNAUTHORIZED)
219	                        .body(axum::body::Body::from(r#"{"error":"invalid API key"}"#))
220	                        .unwrap();
221	                    Ok(response)
222	                }
223	                None => {
224	                    #[allow(clippy::unwrap_used)]
225	                    // SAFETY: see above.
226	                    let response = axum::response::Response::builder()
227	                        .status(axum::http::StatusCode::UNAUTHORIZED)
228	                        .body(axum::body::Body::from(
229	                            r#"{"error":"missing X-API-Key header"}"#,
230	                        ))
231	                        .unwrap();
232	                    Ok(response)
233	                }
234	            }
235	        })
236	    }
237	}
