239	/// Constant-time byte comparison to prevent timing side-channel attacks.
240	fn constant_time_eq(a: &[u8], b: &[u8]) -> bool {
241	    if a.len() != b.len() {
242	        return false;
243	    }
244	    let mut acc: u8 = 0;
245	    for (x, y) in a.iter().zip(b.iter()) {
246	        acc |= x ^ y;
247	    }
248	    acc == 0
249	}
