471	    ) -> Result<Response<RoutedSignal>, Status> {
472	        let req = request.into_inner();
473	        let _session_id = parse_uuid(&req.session_id, "session_id")?;
474	
475	        // Publish each report to the event bus for subscribers
476	        for report in &req.reports {
477	            self.events.eye_reports.publish(EyeReportEvent {
