106	#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
107	pub struct ImmediateOutcome {
108	    pub action_succeeded: bool,
109	    pub results_produced: String,
110	    pub error_message: Option<String>,
111	    pub execution_time_ms: u64,
112	}
