114	impl ImmediateOutcome {
115	    #[must_use] 
116	    pub fn score(&self) -> f32 {
117	        if self.action_succeeded {
118	            1.0
119	        } else {
120	            // Penalize based on error severity (heuristic).
121	            match &self.error_message {
122	                Some(e) if e.contains("timeout") => 0.2,
123	                Some(e) if e.contains("not found") => 0.1,
124	                Some(_) => 0.0,
125	                None => 0.5,
126	            }
127	        }
128	    }
129	}
