1	//! Signal router — the central nervous system hub.
2	//!
3	//! Receives `EyeReports` from all 5 eyes, scores goal relevance,
4	//! suppresses noise, resolves contradictions, and emits a unified
5	//! `RoutedSignal` to the Decision Intelligence Layer.
6	//!
7	//! Pipeline:
8	//! 1. Score each report for goal relevance
9	//! 2. Filter out noise (relevance below threshold)
10	//! 3. Amplify high-relevance signals
11	//! 4. Resolve cross-eye contradictions
12	//! 5. Synthesize unified `RoutedSignal`
13	
14	use std::fmt::Write;
15	
16	use ans_core::signal::{DistractionAlert, EyeName, EyeReport, EyeReportContent, RoutedSignal};
17	
18	use crate::contradiction::ContradictionResolver;
19	
20	/// Minimum relevance score for a report to pass noise suppression.
21	const NOISE_THRESHOLD: f32 = 0.15;
22	
23	/// Eye-specific base weight for relevance scoring.
24	const fn eye_weight(eye: EyeName) -> f32 {
25	    match eye {
26	        EyeName::GoalVerifier => 0.35,
27	        EyeName::PageDiff => 0.25,
28	        EyeName::DomReader => 0.20,
29	        EyeName::Vision => 0.15,
30	        EyeName::ErrorDetector => 0.05,
31	    }
32	}
33	
34	/// The signal router. Single instance per daemon, shared across sessions.
35	pub struct SignalRouter {
36	    resolver: ContradictionResolver,
37	}
38	
39	impl SignalRouter {
40	    #[must_use] 
41	    pub const fn new() -> Self {
42	        Self {
43	            resolver: ContradictionResolver,
44	        }
45	    }
46	
47	    /// Route a batch of eye reports into a unified signal.
48	    pub fn route(&self, reports: &[EyeReport]) -> RoutedSignal {
49	        if reports.is_empty() {
50	            return RoutedSignal {
51	                unified_perception: String::new(),
52	                alerts: Vec::new(),
53	                confidence: 0.0,
54	                recommended_action_hint: None,
55	                contradictions: Vec::new(),
56	            };
57	        }
58	
59	        // 1. Score and filter
60	        let scored: Vec<ScoredReport<'_>> = reports
61	            .iter()
62	            .map(|r| ScoredReport {
63	                report: r,
64	                relevance: compute_relevance(r),
65	            })
66	            .collect();
67	
68	        // 2. Suppress noise
69	        let active: Vec<&ScoredReport<'_>> = scored
70	            .iter()
71	            .filter(|s| s.relevance >= NOISE_THRESHOLD)
72	            .collect();
73	
74	        let reports_for_resolution: Vec<EyeReport> = if active.is_empty() {
75	            // Everything was noise — keep the highest-relevance one as fallback
76	            scored
77	                .iter()
78	                .max_by(|a, b| a.relevance.partial_cmp(&b.relevance).unwrap_or(std::cmp::Ordering::Equal))
79	                .map(|s| s.report.clone())
80	                .into_iter()
81	                .collect()
82	        } else {
83	            active.iter().map(|s| s.report.clone()).collect()
84	        };
85	
86	        // 3. Resolve contradictions
87	        let contradictions = self.resolver.resolve_all(&reports_for_resolution);
88	
89	        // 4. Synthesize unified perception
90	        let parts: Vec<String> = reports_for_resolution
91	            .iter()
92	            .map(format_eye_summary)
93	            .collect();
94	
95	        let unified_perception = parts.join(" | ");
96	
97	        // 5. Compute aggregate confidence
98	        let confidence = if reports_for_resolution.is_empty() {
99	            0.0
100	        } else {
101	            let total: f32 = reports_for_resolution
102	                .iter()
103	                .map(|r| r.confidence * eye_weight(r.eye_name))
104	                .sum();
105	            let max_possible: f32 = reports_for_resolution
106	                .iter()
107	                .map(|r| eye_weight(r.eye_name))
108	                .sum();
109	            if max_possible > 0.0 {
110	                (total / max_possible).clamp(0.0, 1.0)
111	            } else {
112	                0.0
113	            }
114	        };
115	
116	        // 6. Generate action hint
117	        let hint = generate_hint(&reports_for_resolution, &contradictions);
118	
119	        // 7. Collect alerts from error reports
120	        let alerts = collect_alerts(&reports_for_resolution);
121	
122	        RoutedSignal {
123	            unified_perception,
124	            alerts,
125	            confidence,
126	            recommended_action_hint: hint,
127	            contradictions,
128	        }
129	    }
130	}
131	
132	impl Default for SignalRouter {
133	    fn default() -> Self {
134	        Self::new()
135	    }
136	}
137	
138	// ── Internal types ─────────────────────────────────────────────────────
139	
140	struct ScoredReport<'a> {
141	    report: &'a EyeReport,
142	    relevance: f32,
143	}
144	
145	// ── Relevance scoring ──────────────────────────────────────────────────
146	
147	fn compute_relevance(report: &EyeReport) -> f32 {
148	    let base = eye_weight(report.eye_name);
149	    let confidence_factor = report.confidence;
150	    let content_boost = content_relevance_boost(&report.content);
151	    let goal_relevance = report.goal_relevance;
152	
153	    // Weighted blend: eye authority, confidence, content signals, goal alignment
154	    goal_relevance.mul_add(0.3, content_boost.mul_add(0.15, base.mul_add(0.3, confidence_factor * 0.25)))
155	        .clamp(0.0, 1.0)
156	}
157	
158	fn content_relevance_boost(content: &EyeReportContent) -> f32 {
159	    match content {
160	        EyeReportContent::DomReport {
161	            interactive, mode, ..
162	        } => {
163	            let mut boost: f32 = 0.3;
164	            // More interactive elements = more actionable page
165	            if interactive.len() > 5 {
166	                boost += 0.2;
167	            }
168	            if *mode == ans_core::distill::DistillMode::InputFields {
169	                boost += 0.1; // form interaction is high-signal
170	            }
171	            boost.clamp(0.0, 1.0)
172	        }
173	        EyeReportContent::VisionReport {
174	            anomalies,
175	            overlays,
176	            ..
177	        } => {
178	            if !anomalies.is_empty() || !overlays.is_empty() {
179	                0.7 // anomalies are high-signal
180	            } else {
181	                0.3
182	            }
183	        }
184	        EyeReportContent::DiffReport {
185	            visual_diff_pct,
186	            summary,
187	            ..
188	        } => {
189	            if *visual_diff_pct > 20.0 {
190	                0.8
191	            } else if summary.contains("content_update") || summary.contains("form_update") {
192	                0.6
193	            } else if summary.contains("navigation") {
194	                0.4
195	            } else {
196	                0.2
197	            }
198	        }
199	        EyeReportContent::Verification {
200	            sub_goal_advanced,
201	            confidence,
202	            ..
203	        } => {
204	            if *sub_goal_advanced {
205	                0.8 * confidence
206	            } else {
207	                0.3 * confidence
208	            }
209	        }
210	        EyeReportContent::ErrorReport { .. } => 0.9, // errors are always high-signal
211	    }
212	}
213	
214	// ── Perception formatting ──────────────────────────────────────────────
215	
216	fn format_eye_summary(report: &EyeReport) -> String {
217	    let content_summary = match &report.content {
218	        EyeReportContent::DomReport {
219	            elements,
220	            interactive,
221	            mode,
222	        } => {
223	            format!(
224	                "DOM({}): {} el, {} interactive",
225	                mode.as_str(),
226	                elements.len(),
227	                interactive.len()
228	            )
229	        }
230	        EyeReportContent::VisionReport {
231	            visible_elements,
232	            overlays,
233	            page_type,
234	            anomalies,
235	            ..
236	        } => {
237	            let mut s = format!(
238	                "Vision: {} visible, type={}",
239	                visible_elements.len(),
240	                page_type
241	            );
242	            if !overlays.is_empty() {
243	                let _ = write!(s, ", {} overlays", overlays.len());
244	            }
245	            if !anomalies.is_empty() {
246	                let _ = write!(s, ", {} anomalies", anomalies.len());
247	            }
248	            s
249	        }
250	        EyeReportContent::DiffReport {
251	            visual_diff_pct,
252	            summary,
253	            ..
254	        } => {
255	            format!("Diff: {visual_diff_pct:.0}% change ({summary})")
256	        }
257	        EyeReportContent::Verification {
258	            sub_goal_advanced,
259	            confidence,
260	            criteria_status,
261	            ..
262	        } => {
263	            format!(
264	                "Verify: {} (conf={:.0}%, criteria={})",
265	                if *sub_goal_advanced {
266	                    "advanced"
267	                } else {
268	                    "no progress"
269	                },
270	                confidence * 100.0,
271	                criteria_status,
272	            )
273	        }
274	        EyeReportContent::ErrorReport {
275	            failure_type,
276	            description,
277	            ..
278	        } => {
279	            format!("Error: {failure_type} — {description}")
280	        }
281	    };
282	
283	    format!(
284	        "[{} r={:.0}% c={:.0}%] {}",
285	        report.eye_name.as_str(),
286	        report.goal_relevance * 100.0,
287	        report.confidence * 100.0,
288	        content_summary,
289	    )
290	}
291	
292	// ── Action hint generation ─────────────────────────────────────────────
293	
294	fn generate_hint(reports: &[EyeReport], contradictions: &[String]) -> Option<String> {
295	    if !contradictions.is_empty() {
296	        return Some("Cross-eye contradictions detected — verify before acting".into());
297	    }
298	
299	    // Check for error reports
300	    let has_errors = reports
301	        .iter()
302	        .any(|r| matches!(r.content, EyeReportContent::ErrorReport { .. }));
303	
304	    if has_errors {
305	        return Some("Errors detected — attempt recovery before proceeding".into());
306	    }
307	
308	    // Check for high-confidence verifier
309	    let verifications: Vec<_> = reports
310	        .iter()
311	        .filter(|r| matches!(r.content, EyeReportContent::Verification { .. }))
312	        .collect();
313	
314	    if let Some(v) = verifications.first() {
315	        if v.confidence > 0.8 && v.goal_relevance > 0.7 {
316	            if let EyeReportContent::Verification {
317	                sub_goal_advanced: true,
318	                ..
319	            } = &v.content
320	            {
321	                return Some("Goal progressing — continue current strategy".into());
322	            }
323	        }
324	    }
325	
326	    // Check for high-change diff
327	    let diffs: Vec<_> = reports
328	        .iter()
329	        .filter(|r| matches!(r.content, EyeReportContent::DiffReport { .. }))
330	        .collect();
331	
332	    if let Some(d) = diffs.first() {
333	        if let EyeReportContent::DiffReport {
334	            visual_diff_pct, ..
335	        } = &d.content
336	        {
337	            if *visual_diff_pct > 50.0 {
338	                return Some("Major page change — re-assess page state before acting".into());
339	            }
340	        }
341	    }
342	
343	    // Average relevance across all reports
344	    let avg_relevance: f32 =
345	        reports.iter().map(|r| r.goal_relevance).sum::<f32>() / reports.len().max(1) as f32;
346	
347	    if avg_relevance > 0.7 {
348	        Some("High goal relevance — prioritize action".into())
349	    } else if avg_relevance < 0.3 {
350	        Some("Low goal relevance — consider re-navigating".into())
351	    } else {
352	        None
353	    }
354	}
355	
356	// ── Alert collection ───────────────────────────────────────────────────
357	
358	fn collect_alerts(reports: &[EyeReport]) -> Vec<DistractionAlert> {
359	    let mut alerts = Vec::new();
360	
361	    for report in reports {
362	        match &report.content {
363	            EyeReportContent::VisionReport {
364	                anomalies,
365	                overlays,
366	                ..
367	            } => {
368	                for anomaly in anomalies {
369	                    alerts.push(DistractionAlert {
370	                        kind: "vision_anomaly".into(),
371	                        description: anomaly.clone(),
372	                        action_taken: "flagged for review".into(),
373	                    });
374	                }
375	                for overlay in overlays {
376	                    alerts.push(DistractionAlert {
377	                        kind: "overlay_detected".into(),
378	                        description: overlay.clone(),
379	                        action_taken: "dismiss before interaction".into(),
380	                    });
381	                }
382	            }
383	            EyeReportContent::ErrorReport {
384	                failure_type,
385	                description,
386	                should_retry,
387	                ..
388	            } => {
389	                alerts.push(DistractionAlert {
390	                    kind: format!("error_{failure_type}"),
391	                    description: description.clone(),
392	                    action_taken: if *should_retry {
393	                        "will retry".into()
394	                    } else {
395	                        "requires manual intervention".into()
396	                    },
397	                });
398	            }
399	            _ => {}
400	        }
401	    }
402	
403	    alerts
404	}
