1	//! Cross-eye contradiction resolution engine.
2	//!
3	//! When two eyes disagree (e.g. Vision sees a button but DOM Reader
4	//! says it's not interactable), this engine applies the resolution
5	//! hierarchy to produce a consistent view.
6	//!
7	//! Resolution hierarchy (highest authority wins):
8	//! 1. DOM Reader (ground truth for element state)
9	//! 2. Page Diff (ground truth for what changed)
10	//! 3. Goal Verifier (ground truth for goal progress)
11	//! 4. Vision Model (best guess, overridable)
12	//! 5. Error Detector (only consulted on failure)
13	
14	use ans_core::signal::{EyeName, EyeReport, EyeReportContent};
15	
16	/// Resolves cross-eye contradictions and returns resolution notes.
17	pub struct ContradictionResolver;
18	
19	impl ContradictionResolver {
20	    /// Resolution authority: higher number = more authoritative.
21	    const fn authority(eye: EyeName) -> u8 {
22	        match eye {
23	            EyeName::DomReader => 5,
24	            EyeName::PageDiff => 4,
25	            EyeName::GoalVerifier => 3,
26	            EyeName::Vision => 2,
27	            EyeName::ErrorDetector => 1,
28	        }
29	    }
30	
31	    /// Resolve all contradictions in a batch of eye reports.
32	    /// Returns human-readable contradiction resolution notes.
33	    #[must_use] 
34	    pub fn resolve_all(&self, reports: &[EyeReport]) -> Vec<String> {
35	        if reports.len() < 2 {
36	            return Vec::new();
37	        }
38	
39	        let mut contradictions = Vec::new();
40	
41	        // Check every pair of reports from different eyes
42	        for (i, a) in reports.iter().enumerate() {
43	            for b in reports.iter().skip(i + 1) {
44	                if a.eye_name == b.eye_name {
45	                    continue;
46	                }
47	
48	                let conflict = self.detect_conflict(a, b);
49	                if let Some(description) = conflict {
50	                    contradictions.push(description);
51	                }
52	            }
53	        }
54	
55	        contradictions
56	    }
57	
58	    /// Detect whether two reports from different eyes conflict.
59	    fn detect_conflict(&self, a: &EyeReport, b: &EyeReport) -> Option<String> {
60	        let auth_a = Self::authority(a.eye_name);
61	        let auth_b = Self::authority(b.eye_name);
62	
63	        // Only flag when both are high-confidence and their
64	        // content suggests disagreement.
65	        if a.confidence < 0.5 || b.confidence < 0.5 {
66	            return None;
67	        }
68	
69	        let conflict_kind = match (&a.content, &b.content) {
70	            // DOM says element status vs Vision anomalies
71	            (
72	                EyeReportContent::DomReport { .. },
73	                EyeReportContent::VisionReport { anomalies, .. },
74	            ) => {
75	                if anomalies.is_empty() {
76	                    None
77	                } else {
78	                    Some((a, b, auth_a, auth_b, "element visibility vs visual anomaly"))
79	                }
80	            }
81	            // Vision vs DOM (reversed order)
82	            (
83	                EyeReportContent::VisionReport { anomalies, .. },
84	                EyeReportContent::DomReport { .. },
85	            ) => {
86	                if anomalies.is_empty() {
87	                    None
88	                } else {
89	                    Some((b, a, auth_b, auth_a, "visual anomaly vs element state"))
90	                }
91	            }
92	            // Diff says no change but Verifier says progress
93	            (
94	                EyeReportContent::DiffReport { summary, .. },
95	                EyeReportContent::Verification {
96	                    sub_goal_advanced, ..
97	                },
98	            ) => {
99	                let is_static = summary.contains("no_change") || summary.contains("cosmetic");
100	                if is_static && *sub_goal_advanced {
101	                    Some((
102	                        a,
103	                        b,
104	                        auth_a,
105	                        auth_b,
106	                        "no visual change vs goal progress claimed",
107	                    ))
108	                } else {
109	                    None
110	                }
111	            }
112	            // Verifier vs Diff (reversed)
113	            (
114	                EyeReportContent::Verification {
115	                    sub_goal_advanced, ..
116	                },
117	                EyeReportContent::DiffReport { summary, .. },
118	            ) => {
119	                let is_static = summary.contains("no_change") || summary.contains("cosmetic");
120	                if is_static && *sub_goal_advanced {
121	                    Some((
122	                        b,
123	                        a,
124	                        auth_b,
125	                        auth_a,
126	                        "goal progress claimed vs no visual change",
127	                    ))
128	                } else {
129	                    None
130	                }
131	            }
132	            // Error detector vs any — Error only consulted on failure
133	            (EyeReportContent::ErrorReport { .. }, _) => {
134	                // Error is lowest authority; other eye's view may override
135	                if auth_b > auth_a {
136	                    Some((b, a, auth_b, auth_a, "non-error eye overrides error report"))
137	                } else {
138	                    None
139	                }
140	            }
141	            (_, EyeReportContent::ErrorReport { .. }) => {
142	                if auth_a > auth_b {
143	                    Some((a, b, auth_a, auth_b, "non-error eye overrides error report"))
144	                } else {
145	                    None
146	                }
147	            }
148	            _ => None,
149	        };
150	
151	        conflict_kind.map(|(winner, loser, w_auth, l_auth, reason)| {
152	            format!(
153	                "{} overrides {} [{}]: authority {} > {}",
154	                winner.eye_name.as_str(),
155	                loser.eye_name.as_str(),
156	                reason,
157	                w_auth,
158	                l_auth,
159	            )
160	        })
161	    }
162	}
