165	        assert_eq!(tracker.mode(), BudgetMode::Emergency);
166	
167	        tracker.configure(BudgetConfig {
168	            daily_spend_limit_cents: 10000,
169	            ..Default::default()
170	        });
171	        assert_eq!(tracker.mode(), BudgetMode::Normal);
172	    }
173	
174	    #[test]
175	    fn test_status_snapshot() {
176	        let tracker = BudgetTracker::new(BudgetConfig::default());
177	        let status = tracker.status();
178	        assert_eq!(status.mode, BudgetMode::Normal);
179	        assert_eq!(status.spent_cents, 0);
180	    }
181	}
