1	//! 4-level cost circuit breaker.
2	//!
3	//! Transitions are one-way within a session (tightening only):
4	//! Normal → Conservative → Critical → Emergency
5	//!
6	//! The circuit breaker RESETS to Normal when a new session starts
7	//! (fresh budget). It does not auto-recover within a session.
8	
9	use ans_core::budget::BudgetMode;
10	
11	/// The circuit breaker state machine.
12	pub struct CircuitBreaker {
13	    mode: BudgetMode,
14	}
15	
16	impl CircuitBreaker {
17	    #[must_use] 
18	    pub const fn new() -> Self {
19	        Self {
20	            mode: BudgetMode::Normal,
21	        }
22	    }
23	
24	    #[must_use] 
25	    pub const fn current_mode(&self) -> BudgetMode {
26	        self.mode
27	    }
28	
29	    pub fn update(&mut self, remaining_pct: f32) {
30	        let new_mode = BudgetMode::from_remaining_pct(remaining_pct);
31	        if new_mode > self.mode {
32	            self.mode = new_mode;
33	        }
34	    }
35	}
36	
37	impl Default for CircuitBreaker {
38	    fn default() -> Self {
39	        Self::new()
40	    }
41	}
