105	// ── Enum ↔ string converters ────────────────────────────────────────
106	
107	#[must_use] 
108	pub const fn goal_status_to_str(status: GoalStatus) -> &'static str {
109	    match status {
110	        GoalStatus::Pending => "pending",
111	        GoalStatus::Active => "active",
112	        GoalStatus::Completed => "completed",
113	        GoalStatus::Failed => "failed",
114	        GoalStatus::Blocked => "blocked",
115	    }
116	}
117	
118	#[must_use] 
119	pub fn str_to_goal_status(s: &str) -> GoalStatus {
120	    match s {
121	        "active" => GoalStatus::Active,
122	        "completed" => GoalStatus::Completed,
123	        "failed" => GoalStatus::Failed,
124	        "blocked" => GoalStatus::Blocked,
125	        _ => GoalStatus::Pending,
126	    }
127	}
128	
129	const fn sub_goal_status_to_str(status: SubGoalStatus) -> &'static str {
130	    match status {
131	        SubGoalStatus::Pending => "pending",
132	        SubGoalStatus::Active => "active",
133	        SubGoalStatus::Done => "done",
134	        SubGoalStatus::Blocked => "blocked",
135	    }
136	}
137	
138	fn str_to_sub_goal_status(s: &str) -> SubGoalStatus {
139	    match s {
140	        "active" => SubGoalStatus::Active,
141	        "done" => SubGoalStatus::Done,
142	        "blocked" => SubGoalStatus::Blocked,
143	        _ => SubGoalStatus::Pending,
144	    }
145	}
