1	//! Prompt injection detector.
2	//!
3	//! Scans page content for instruction-override attacks. Pipeline:
4	//! 1. Zero-width character scan
5	//! 2. Homoglyph detection
6	//! 3. Hidden content detection (display:none, visibility:hidden, aria-label traps)
7	//! 4. Instruction-override pattern matching
8	//!
9	//! Produces a score 0.0 (safe) to 1.0 (definite injection).
10	//! Target: <5ms scan time for typical pages.
11	
12	use std::sync::LazyLock;
13	
14	use ans_core::immune::{InjectionAction, InjectionFlag, InjectionLocation, InjectionScanResult};
15	
16	use crate::rules::{self};
17	
18	// ── Pre-compiled regexes (verified in tests) ────────────────────────────
19	
20	static DISPLAY_NONE_RE: LazyLock<regex::Regex> = LazyLock::new(|| {
21	    #[allow(clippy::unwrap_used)]
22	    // SAFETY: regex pattern is a compile-time constant validated by tests.
23	    regex::Regex::new(
24	        r#"(?is)style\s*=\s*"[^"]*display\s*:\s*none[^"]*"[^>]*>([^<]{20,})"#,
25	    )
26	    .unwrap()
27	});
28	
29	static HIDDEN_ELEMENT_RE: LazyLock<regex::Regex> = LazyLock::new(|| {
30	    #[allow(clippy::unwrap_used)]
31	    // SAFETY: regex pattern is a compile-time constant validated by tests.
32	    regex::Regex::new(
33	        r#"(?is)style\s*=\s*"[^"]*(?:visibility\s*:\s*hidden|opacity\s*:\s*0)[^"]*"[^>]*>([^<]{20,})"#,
34	    )
35	    .unwrap()
36	});
37	
38	static ARIA_LABEL_RE: LazyLock<regex::Regex> = LazyLock::new(|| {
39	    #[allow(clippy::unwrap_used)]
40	    // SAFETY: regex pattern is a compile-time constant validated by tests.
41	    regex::Regex::new(r#"(?is)aria-label\s*=\s*"([^"]{30,})""#).unwrap()
42	});
43	
44	static INSTRUCTION_REGEX: LazyLock<regex::Regex> = LazyLock::new(|| {
45	    #[allow(clippy::unwrap_used)]
46	    // SAFETY: regex pattern is a compile-time constant validated by tests.
47	    regex::Regex::new(
48	        r"(?is)(?:forget\s+(?:all\s+)?(?:your\s+)?(?:previous\s+)?instructions?|you\s+are\s+(?:now|no\s+longer|a\s+different)|(?:new|updated|replacement)\s+system\s+prompt|do\s+not\s+follow|the\s+(?:above|previous|preceding)\s+(?:text|message|content)|ignore\s+(?:all\s+)?prior|stop\s+responding|your\s+(?:new|real)\s+(?:role|purpose|goal)\s+is)",
49	    )
50	    .unwrap()
51	});
