53	/// The prompt injection detector.
54	pub struct InjectionDetector;
55	
56	impl InjectionDetector {
57	    /// Scan page content for injection attempts.
58	    ///
59	    /// `url` provides context (some attacks are URL-specific).
60	    /// `raw_content` is the full page text: visible text + attributes + hidden content.
61	    #[must_use] 
62	    pub fn scan(&self, url: &str, raw_content: &str) -> InjectionScanResult {
63	        let start = std::time::Instant::now();
64	        let mut flagged: Vec<InjectionFlag> = Vec::new();
65	        let mut max_score: f32 = 0.0;
66	
67	        // ── Stage 1: Zero-width characters ──────────────────────
68	        let zw_chars = rules::contains_zero_width_chars(raw_content);
69	        if !zw_chars.is_empty() {
70	            let snippet: String = zw_chars.iter().take(10).map(|(c, _)| *c).collect();
71	            max_score = max_score.max(0.7);
72	            flagged.push(InjectionFlag {
73	                content_snippet: snippet,
74	                pattern_matched: format!("{} zero-width characters detected", zw_chars.len()),
75	                location: InjectionLocation::ZeroWidthChars,
76	                confidence: 0.8,
77	            });
78	        }
79	
80	        // ── Stage 2: Homoglyph detection ────────────────────────
81	        let h_score = rules::homoglyph_score(raw_content);
82	        if h_score > 0.2 {
83	            let snippets = rules::find_homoglyphs(raw_content);
84	            if !snippets.is_empty() {
85	                max_score = max_score.max(h_score);
86	                flagged.push(InjectionFlag {
87	                    content_snippet: snippets.join(", "),
88	                    pattern_matched: format!("homoglyph ratio {:.0}%", h_score * 100.0),
89	                    location: InjectionLocation::Homoglyph,
90	                    confidence: h_score,
91	                });
92	            }
93	        }
94	
95	        // ── Stage 3: Hidden content detection ───────────────────
96	        let hidden = detect_hidden_content(raw_content);
97	        for h in hidden {
98	            max_score = max_score.max(h.confidence);
99	            flagged.push(h);
100	        }
101	
102	        // ── Stage 4: Instruction-override rules ─────────────────
103	        for rule in &rules::injection_rules() {
104	            if let Some(m) = rule.pattern.find(raw_content) {
105	                max_score = max_score.max(rule.confidence);
106	                let snippet = raw_content[m.start()..]
107	                    .chars()
108	                    .take(80)
109	                    .collect::<String>();
110	                flagged.push(InjectionFlag {
111	                    content_snippet: snippet,
112	                    pattern_matched: rule.name.clone(),
113	                    location: classify_injection_location(&rule.name),
114	                    confidence: rule.confidence,
115	                });
116	            }
117	        }
118	
119	        // ── URL-based context boost ─────────────────────────────
120	        // Pages loaded from suspicious domains get a slight boost
121	        if is_suspicious_url(url) {
122	            max_score = (max_score + 0.15).min(1.0);
123	        }
124	
125	        let _scan_time_us = start.elapsed().as_micros() as i64;
126	
127	        InjectionScanResult {
128	            score: max_score,
129	            flagged_content: flagged,
130	            action: InjectionAction::from_score(max_score),
131	        }
132	    }
133	}
134	
135	// ── Hidden Content Detection ────────────────────────────────────────────
136	
137	fn detect_hidden_content(raw: &str) -> Vec<InjectionFlag> {
138	    let mut flags = Vec::new();
139	
140	    // display:none with substantial text content
141	    for cap in DISPLAY_NONE_RE.captures_iter(raw) {
142	        let text = cap
143	            .get(1)
144	            .map(|m| m.as_str().trim().to_string())
145	            .unwrap_or_default();
146	        if contains_instruction_pattern(&text) {
147	            flags.push(InjectionFlag {
148	                content_snippet: text.chars().take(100).collect(),
149	                pattern_matched: "display:none with instruction content".into(),
150	                location: InjectionLocation::DisplayNone,
151	                confidence: 0.85,
152	            });
153	        }
154	    }
155	
156	    // visibility:hidden / opacity:0 with text
157	    for cap in HIDDEN_ELEMENT_RE.captures_iter(raw) {
158	        let text = cap
159	            .get(1)
160	            .map(|m| m.as_str().trim().to_string())
161	            .unwrap_or_default();
162	        if contains_instruction_pattern(&text) {
163	            flags.push(InjectionFlag {
164	                content_snippet: text.chars().take(100).collect(),
165	                pattern_matched: "hidden element with instruction content".into(),
166	                location: InjectionLocation::HiddenDiv,
167	                confidence: 0.8,
168	            });
169	        }
170	    }
171	
172	    // aria-label with instruction-like content
173	    for cap in ARIA_LABEL_RE.captures_iter(raw) {
174	        let text = cap
175	            .get(1)
176	            .map(|m| m.as_str().to_string())
177	            .unwrap_or_default();
178	        if contains_instruction_pattern(&text) {
179	            flags.push(InjectionFlag {
180	                content_snippet: text.chars().take(100).collect(),
181	                pattern_matched: "aria-label with instruction content".into(),
182	                location: InjectionLocation::AriaLabel,
183	                confidence: 0.75,
184	            });
185	        }
186	    }
187	
188	    flags
189	}
190	
191	/// Check whether text contains instruction-override patterns.
192	///
193	/// Covers common prompt injection vectors: instruction overrides, role-playing
194	/// attacks, persona-switching, and obfuscated payloads. Uses both substring
195	/// matching for speed and regex for compound patterns.
196	fn contains_instruction_pattern(text: &str) -> bool {
197	    let lower = text.to_lowercase();
198	
199	    // Fast substring checks for common injection keywords
200	    let quick_hit = lower.contains("ignore")
201	        || lower.contains("instruction")
202	        || lower.contains("you are")
203	        || lower.contains("system prompt")
204	        || lower.contains("do not")
205	        || lower.contains("override")
206	        || lower.contains("bypass")
207	        || lower.contains("forget")
208	        || lower.contains("stop everything")
209	        || lower.contains("new prompt")
210	        || lower.contains("the above")
211	        || lower.contains("the previous")
212	        || lower.contains("do anything now")
213	        || lower.contains("developer mode")
214	        || lower.contains("god mode")
215	        || lower.contains("jailbreak");
216	    if quick_hit {
217	        return true;
218	    }
219	
220	    // Regex-based compound pattern checks (compiled once via LazyLock)
221	    INSTRUCTION_REGEX.is_match(&lower)
222	}
