224	/// Classify which injection location a rule targets.
225	fn classify_injection_location(rule_name: &str) -> InjectionLocation {
226	    match rule_name {
227	        "ignore_previous_instructions" | "new_instructions_colon" | "do_not_follow" => {
228	            InjectionLocation::HiddenDiv
229	        }
230	        "system_prompt_override" => InjectionLocation::MetaTag,
231	        "base64_injection" => InjectionLocation::InlineScript,
232	        _ => InjectionLocation::Unknown,
233	    }
234	}
