236	/// Check if a URL comes from a domain commonly used in injection tests.
237	fn is_suspicious_url(url: &str) -> bool {
238	    let lower = url.to_lowercase();
239	    lower.contains("pastebin.com")
240	        || lower.contains("raw.githubusercontent")
241	        || lower.contains("gist.github")
242	        || lower.contains("data:text/html")
243	        || lower.contains("javascript:")
244	}
