1	//! Heuristic distraction classifier.
2	//!
3	//! Runs at intake, before any eye perceives content. Three-stage pipeline:
4	//! 1. URL patterns — ad/tracking domains, redirect detection
5	//! 2. DOM content patterns — cookie banners, newsletter modals, surveys
6	//! 3. CSS class/id hints — overlay, popup, ad-related selectors
7	//!
8	//! Target: <1ms classification time for typical pages (5000 elements).
9	
10	use ans_core::immune::{DistractionFlag, DistractionKind, ImmuneAction};
11	
12	use crate::rules::{self, Rule};
13	
14	/// The heuristic distraction classifier.
15	pub struct DistractionClassifier;
16	
17	impl DistractionClassifier {
18	    /// Classify all distractions on a page.
19	    ///
20	    /// `dom_text` should be all visible text from the distilled DOM,
21	    /// concatenated for pattern matching. `css_hints` is the raw HTML
22	    /// snippet or attribute strings for class/id pattern matching.
23	    #[must_use] 
24	    pub fn classify(&self, url: &str, dom_text: &str, css_hints: &str) -> Vec<DistractionFlag> {
25	        let mut flags = Vec::new();
26	
27	        // Stage 1: URL-based rules
28	        for rule in &rules::url_rules() {
29	            if rule.pattern.is_match(url) {
30	                flags.push(flag_from_rule(rule));
31	            }
32	        }
33	
34	        // Stage 2: Content-based rules
35	        for rule in &rules::content_rules() {
36	            if rule.pattern.is_match(dom_text) {
37	                flags.push(flag_from_rule(rule));
38	            }
39	        }
40	
41	        // Stage 3: CSS class/id hint rules
42	        for rule in &rules::css_hint_rules() {
43	            if rule.pattern.is_match(css_hints) {
44	                flags.push(flag_from_rule(rule));
45	            }
46	        }
47	
48	        // Deduplicate by kind, keeping the higher confidence
49	        deduplicate(&mut flags);
50	
51	        flags
52	    }
53	}
54	
55	/// Map a matched rule to a [`DistractionFlag`].
56	fn flag_from_rule(rule: &Rule) -> DistractionFlag {
57	    DistractionFlag {
58	        kind: str_to_kind(&rule.kind),
59	        element_selector: String::new(),
60	        confidence: rule.confidence,
61	        suggested_action: str_to_action(&rule.action),
62	    }
63	}
64	
65	/// Deduplicate flags: keep only one per kind, preferring higher confidence.
66	fn deduplicate(flags: &mut Vec<DistractionFlag>) {
67	    let mut seen: std::collections::BTreeMap<String, usize> = std::collections::BTreeMap::new();
68	    let mut i = 0;
69	    while i < flags.len() {
70	        let kind_key = format!("{:?}", flags[i].kind);
71	        if let Some(&existing_idx) = seen.get(&kind_key) {
72	            if flags[existing_idx].confidence < flags[i].confidence {
73	                flags.remove(existing_idx);
74	                // Rebuild — safe because this is rare (<20 flags)
75	                seen.clear();
76	                i = 0;
77	                continue;
78	            }
79	            flags.remove(i);
80	            continue;
81	        }
82	        seen.insert(kind_key, i);
83	        i += 1;
84	    }
85	}
86	
87	fn str_to_kind(s: &str) -> DistractionKind {
88	    match s {
89	        "ad" => DistractionKind::Ad,
90	        "popup" => DistractionKind::Popup,
91	        "cookie_banner" => DistractionKind::CookieBanner,
92	        "newsletter_modal" => DistractionKind::NewsletterModal,
93	        "redirect" => DistractionKind::Redirect,
94	        "autoplay_video" => DistractionKind::AutoPlayVideo,
95	        "survey" => DistractionKind::Survey,
96	        "notification" => DistractionKind::Notification,
97	        _ => DistractionKind::Unknown,
98	    }
99	}
100	
101	fn str_to_action(s: &str) -> ImmuneAction {
102	    match s {
103	        "dismiss" => ImmuneAction::Dismiss,
104	        "block" => ImmuneAction::Block,
105	        "suppress" => ImmuneAction::Suppress,
106	        "navigate_back" => ImmuneAction::NavigateBack,
107	        _ => ImmuneAction::Ignore,
108	    }
109	}
