1	//! Page diff engine.
2	//!
3	//! Compares two [`DistilledPage`] snapshots using element-identity matching.
4	//! Runs automatically after every action — the Goal Verifier consumes
5	//! the diff to check sub-goal criteria.
6	//!
7	//! Algorithm: identity-key matching (not full Zhang-Shasha tree edit distance,
8	//! which is O(n⁴) and wrong fit for DOM). Each element gets an identity label
9	//! from its tag + text prefix + role. Elements are matched by identity across
10	//! the two trees. Unmatched elements are added/removed; matched elements with
11	//! different attributes are modified.
12	
13	use std::collections::HashMap;
14	
15	use ans_core::distill::DistilledPage;
16	
17	use crate::types::{identity_label, DiffOutput, ElementChange, ElementModification};
18	
19	/// The page differ. Created once, called after every action.
20	pub struct PageDiffer;
21	
22	impl PageDiffer {
23	    /// Compute the diff between two page snapshots.
24	    ///
25	    /// `before` is the page state before the action.
26	    /// `after` is the page state after the action.
27	    pub fn diff(&self, before: &DistilledPage, after: &DistilledPage) -> DiffOutput {
28	        // URL change means navigation — entirely different page
29	        if before.url != after.url {
30	            return DiffOutput {
31	                added: vec![],
32	                removed: vec![],
33	                modified: vec![],
34	                visual_diff_pct: 1.0,
35	                summary: "navigation".into(),
36	                is_same_page: false,
37	            };
38	        }
39	
40	        let before_labels: Vec<String> = before.elements.iter().map(identity_label).collect();
41	        let after_labels: Vec<String> = after.elements.iter().map(identity_label).collect();
42	
43	        // Build a frequency map of identity labels for matching
44	        let _before_label_counts = label_counts(&before_labels);
45	        let _after_label_counts = label_counts(&after_labels);
46	
47	        // Match by identity: elements whose label appears in both trees
48	        // are "same" elements, possibly modified
49	        let mut added: Vec<ElementChange> = Vec::new();
50	        let mut removed: Vec<ElementChange> = Vec::new();
51	        let mut modified: Vec<ElementModification> = Vec::new();
52	
53	        // Track which after-indices have been matched to avoid double-matching
54	        let mut after_used: Vec<bool> = vec![false; after.elements.len()];
55	
56	        // For each "before" element, find a matching "after" element
57	        for (i, label) in before_labels.iter().enumerate() {
58	            let before_el = &before.elements[i];
59	
60	            // Try to find a matching element in the after set
61	            if let Some(j) = find_match(label, &after_labels, &after_used) {
62	                after_used[j] = true;
63	                let after_el = &after.elements[j];
64	
65	                // Check for attribute modifications
66	                let mods = compare_attributes(before_el, after_el);
67	                modified.extend(mods);
68	
69	                // Check for text changes
70	                if before_el.text != after_el.text {
71	                    modified.push(ElementModification {
72	                        selector: crate::types::element_selector(after_el),
73	                        attribute_name: "text".into(),
74	                        old_value: truncate_for_diff(&before_el.text),
75	                        new_value: truncate_for_diff(&after_el.text),
76	                    });
77	                }
78	            } else {
79	                // No match — this element was removed
80	                removed.push(ElementChange {
81	                    tag: before_el.tag.clone(),
82	                    text: before_el.text.clone(),
83	                    selector: crate::types::element_selector(before_el),
84	                    index: i as i32,
85	                });
86	            }
87	        }
88	
89	        // Find elements that are in "after" but not in "before" (added)
90	        for (j, used) in after_used.iter().enumerate() {
91	            if !used {
92	                let el = &after.elements[j];
93	                // Skip elements that are so common they produce false positives
94	                if skip_noise_element(el) {
95	                    continue;
96	                }
97	                added.push(ElementChange {
98	                    tag: el.tag.clone(),
99	                    text: el.text.clone(),
100	                    selector: crate::types::element_selector(el),
101	                    index: j as i32,
102	                });
103	            }
104	        }
105	
106	        // Also detect new distractions
107	        let new_distractions = detect_new_distractions(before, after);
108	        if !new_distractions.is_empty() {
109	            added.extend(new_distractions);
110	        }
111	
112	        let total = (before.elements.len() + after.elements.len()).max(1) as f32;
113	        let changed = (added.len() + removed.len() + modified.len()) as f32;
114	        let visual_diff_pct = (changed / total).clamp(0.0, 1.0);
115	
116	        // Classify the change
117	        let summary = classify_change(&added, &removed, &modified, before, after);
118	
119	        DiffOutput {
120	            added,
121	            removed,
122	            modified,
123	            visual_diff_pct,
124	            summary,
125	            is_same_page: true,
126	        }
127	    }
128	}
129	
130	/// Build a frequency count of labels.
131	fn label_counts(labels: &[String]) -> HashMap<&str, usize> {
132	    let mut counts = HashMap::new();
133	    for label in labels {
134	        *counts.entry(label.as_str()).or_insert(0) += 1;
135	    }
136	    counts
137	}
138	
139	/// Find an unused match for `label` in the `after_labels` list.
140	fn find_match(label: &str, after_labels: &[String], after_used: &[bool]) -> Option<usize> {
141	    after_labels
142	        .iter()
143	        .enumerate()
144	        .filter(|(j, _)| !after_used[*j])
145	        .find(|(_, l)| l.as_str() == label)
146	        .map(|(j, _)| j)
147	}
148	
149	/// Compare attributes of two matched elements. Returns attribute-level modifications.
150	fn compare_attributes(
151	    before: &ans_core::distill::DistilledElement,
152	    after: &ans_core::distill::DistilledElement,
153	) -> Vec<ElementModification> {
154	    let selector = crate::types::element_selector(after);
155	    let mut mods = Vec::new();
156	
157	    for (key, before_val) in &before.attributes {
158	        match after.attributes.get(key) {
159	            Some(after_val) if after_val != before_val => {
160	                mods.push(ElementModification {
161	                    selector: selector.clone(),
162	                    attribute_name: key.clone(),
163	                    old_value: before_val.clone(),
164	                    new_value: after_val.clone(),
165	                });
166	            }
167	            None => {
168	                mods.push(ElementModification {
169	                    selector: selector.clone(),
170	                    attribute_name: key.clone(),
171	                    old_value: before_val.clone(),
172	                    new_value: String::new(),
173	                });
174	            }
175	            _ => {}
176	        }
177	    }
178	    mods
179	}
180	
181	/// Skip noise elements that are too generic to produce meaningful diff entries.
182	fn skip_noise_element(el: &ans_core::distill::DistilledElement) -> bool {
183	    // Skip empty text-less elements that appear and disappear with layout shifts
184	    el.text.trim().is_empty()
185	        && !["button", "input", "select", "textarea", "a"].contains(&el.tag.as_str())
186	}
187	
188	/// Truncate text for diff display.
189	fn truncate_for_diff(text: &str) -> String {
190	    if text.len() > 100 {
191	        format!("{}...", &text[..100])
192	    } else {
193	        text.to_string()
194	    }
195	}
196	
197	/// Detect distractions that appeared in the new page but not the old.
198	fn detect_new_distractions(before: &DistilledPage, after: &DistilledPage) -> Vec<ElementChange> {
199	    let before_has_ads = before
200	        .semantic_blocks
201	        .iter()
202	        .any(|b| matches!(b.block_type, ans_core::distill::BlockType::Ad));
203	    let after_has_ads = after
204	        .semantic_blocks
205	        .iter()
206	        .any(|b| matches!(b.block_type, ans_core::distill::BlockType::Ad));
207	
208	    if !before_has_ads && after_has_ads {
209	        // Find ad blocks in after
210	        after
211	            .semantic_blocks
212	            .iter()
213	            .filter(|b| matches!(b.block_type, ans_core::distill::BlockType::Ad))
214	            .filter_map(|b| {
215	                b.element_indices.first().and_then(|&i| {
216	                    after.elements.get(i).map(|el| ElementChange {
217	                        tag: el.tag.clone(),
218	                        text: "Ad detected".into(),
219	                        selector: crate::types::element_selector(el),
220	                        index: i as i32,
221	                    })
222	                })
223	            })
224	            .collect()
225	    } else {
226	        vec![]
227	    }
228	}
229	
230	/// Classify the overall change type from the diff details.
231	fn classify_change(
232	    added: &[ElementChange],
233	    removed: &[ElementChange],
234	    modified: &[ElementModification],
235	    _before: &DistilledPage,
236	    after: &DistilledPage,
237	) -> String {
238	    let total_changes = added.len() + removed.len() + modified.len();
239	
240	    if total_changes == 0 {
241	        return "no_change".into();
242	    }
243	
244	    // Check for error states
245	    let after_text: String = after
246	        .elements
247	        .iter()
248	        .map(|el| el.text.as_str())
249	        .collect::<Vec<_>>()
250	        .join(" ");
251	    let after_lower = after_text.to_lowercase();
252	
253	    let error_patterns = [
254	        "error",
255	        "not found",
256	        "404",
257	        "500",
258	        "access denied",
259	        "forbidden",
260	    ];
261	    if error_patterns.iter().any(|p| after_lower.contains(p)) {
262	        return "error_state".into();
263	    }
264	
265	    // Check for distraction appearance
266	    let distraction_added = added.iter().any(|c| {
267	        c.text.contains("Ad detected") || c.text.contains("cookie") || c.text.contains("popup")
268	    });
269	    if distraction_added {
270	        return "distraction_appeared".into();
271	    }
272	
273	    // Check for form updates
274	    let form_tags = ["input", "select", "textarea", "button", "form"];
275	    let has_form_change = added.iter().any(|c| form_tags.contains(&c.tag.as_str()))
276	        || removed.iter().any(|c| form_tags.contains(&c.tag.as_str()))
277	        || modified.iter().any(|m| {
278	            ["value", "checked", "selected", "disabled"].contains(&m.attribute_name.as_str())
279	        });
280	
281	    if has_form_change {
282	        return "form_update".into();
283	    }
284	
285	    // Check if only cosmetic changes (style, class)
286	    let only_cosmetic = modified.iter().all(|m| {
287	        ["style", "class", "data-"]
288	            .iter()
289	            .any(|p| m.attribute_name.starts_with(p))
290	    }) && added.is_empty()
291	        && removed.is_empty();
292	
293	    if only_cosmetic {
294	        return "cosmetic_change".into();
295	    }
296	
297	    // Check for content text changes
298	    let has_text_change = modified.iter().any(|m| m.attribute_name == "text");
299	    if has_text_change {
300	        return "content_update".into();
301	    }
302	
303	    // Default
304	    "content_update".into()
305	}
