1	//! Diff-specific types: tree nodes, edit operations, cost functions.
2	//!
3	//! Each DOM element becomes a `DiffNode` with a label derived from its
4	//! tag + text prefix + role. The element-identity matching algorithm
5	//! uses these labels to pair elements across page snapshots.
6	
7	use ans_core::distill::DistilledElement;
8	
9	/// A single edit operation produced by the differ.
10	#[derive(Debug, Clone, PartialEq, Eq)]
11	pub enum EditOp {
12	    Insert {
13	        index: usize,
14	        label: String,
15	    },
16	    Delete {
17	        index: usize,
18	    },
19	    Relabel {
20	        index: usize,
21	        old: String,
22	        new: String,
23	    },
24	}
25	
26	/// A node in the labeled ordered tree used for diffing.
27	#[derive(Debug, Clone)]
28	pub struct DiffNode {
29	    pub id: usize,
30	    /// Identity label: `format!("{tag}|{text_prefix}|{role}")`
31	    pub label: String,
32	    /// Indices into the tree's node array for children.
33	    pub children: Vec<usize>,
34	    /// Index into the source `DistilledPage.elements`.
35	    pub element_index: usize,
36	}
37	
38	/// An element that appeared in the new page but not in the old.
39	#[derive(Debug, Clone)]
40	pub struct ElementChange {
41	    pub tag: String,
42	    pub text: String,
43	    pub selector: String,
44	    pub index: i32,
45	}
46	
47	/// An element whose attributes changed between snapshots.
48	#[derive(Debug, Clone)]
49	pub struct ElementModification {
50	    pub selector: String,
51	    pub attribute_name: String,
52	    pub old_value: String,
53	    pub new_value: String,
54	}
55	
56	/// Build an identity label from a distilled element.
57	#[must_use] 
58	pub fn identity_label(el: &DistilledElement) -> String {
59	    let text_prefix: String = el.text.chars().take(50).collect();
60	    let role = el.role.as_deref().unwrap_or("");
61	    format!("{}|{}|{}", el.tag, text_prefix, role)
62	}
63	
64	/// Build a CSS selector from element attributes.
65	#[must_use] 
66	pub fn element_selector(el: &DistilledElement) -> String {
67	    if let Some(id) = el.attributes.get("id") {
68	        if !id.is_empty() && is_valid_css_id(id) {
69	            return format!("#{id}");
70	        }
71	    }
72	    if let Some(class) = el.attributes.get("class") {
73	        let classes: Vec<&str> = class
74	            .split_whitespace()
75	            .filter(|c| is_valid_css_class(c))
76	            .take(2)
77	            .collect();
78	        if !classes.is_empty() {
79	            return format!("{}.{}", el.tag, classes.join("."));
80	        }
81	    }
82	    el.tag.clone()
83	}
84	
85	fn is_valid_css_id(id: &str) -> bool {
86	    id.chars()
87	        .all(|c| c.is_alphanumeric() || c == '-' || c == '_')
88	}
89	
90	fn is_valid_css_class(class: &str) -> bool {
91	    !class.is_empty()
92	        && class
93	            .chars()
94	            .all(|c| c.is_alphanumeric() || c == '-' || c == '_')
95	}
