1	//! DOM distillation engine.
2	//!
3	//! Takes raw CDP DOM snapshots and produces [`DistilledPage`] output.
4	//! Three modes: `TextOnly`, `InputFields`, `AllFields`. Strips distractions,
5	//! annotates interactive elements, and segments semantic blocks.
6	
7	pub mod engine;
8	pub mod semantic;
9	pub mod serialization;
