1	//! Serialization between core domain types and protobuf-generated types.
2	//!
3	//! Converts [`DistilledPage`] ↔ [`DistilledDom`] for the gRPC server.
4	
5	use ans_core::distill::{
6	    BlockType, BoundingBox, DistillMode, DistilledElement, DistilledPage, InteractiveElement,
7	    InteractiveType,
8	};
9	use ans_core::immune::{DistractionFlag, DistractionKind, ImmuneAction};
10	
11	// ── Core → Proto ──────────────────────────────────────────────────────
12	
13	/// Convert a core [`DistilledPage`] into the protobuf [`DistilledDom`] message.
14	pub fn distilled_page_to_proto(page: &DistilledPage) -> ans_proto::ans::DistilledDom {
15	    ans_proto::ans::DistilledDom {
16	        mode: page.mode.as_str().to_string(),
17	        url: page.url.clone(),
18	        title: page.title.clone(),
19	        elements: page.elements.iter().map(element_to_proto).collect(),
20	        interactive: page.interactive.iter().map(interactive_to_proto).collect(),
21	        semantic_blocks: page
22	            .semantic_blocks
23	            .iter()
24	            .map(semantic_block_to_proto)
25	            .collect(),
26	        distraction_flags: page
27	            .distraction_flags
28	            .iter()
29	            .map(distraction_to_proto)
30	            .collect(),
31	        timestamp: page.timestamp.timestamp_millis(),
32	    }
33	}
34	
35	fn element_to_proto(el: &DistilledElement) -> ans_proto::ans::DistilledElement {
36	    ans_proto::ans::DistilledElement {
37	        tag: el.tag.clone(),
38	        text: el.text.clone(),
39	        attributes: el.attributes.clone(),
40	        role: el.role.clone().unwrap_or_default(),
41	        is_visible: el.is_visible,
42	        bounding_box: el.bounding_box.map(bbox_to_proto),
43	        children: el.children.iter().map(|&c| c as i32).collect(),
44	    }
45	}
46	
47	fn interactive_to_proto(el: &InteractiveElement) -> ans_proto::ans::InteractiveElement {
48	    ans_proto::ans::InteractiveElement {
49	        selector: el.selector.clone(),
50	        element_type: interactive_type_to_str(&el.element_type).to_string(),
51	        label: el.label.clone(),
52	        placeholder: el.placeholder.clone().unwrap_or_default(),
53	        current_value: el.current_value.clone().unwrap_or_default(),
