49	/// Build [`ActionCheckResponse`] from distraction + injection scan results.
50	#[must_use] 
51	pub fn build_action_check_response(
52	    distractions: &[DistractionFlag],
53	    injection: &InjectionScanResult,
54	) -> ans_proto::ans::ActionCheckResponse {
55	    let mut allowed = true;
56	    let mut reasons: Vec<String> = Vec::new();
57	    let mut distraction_alerts: Vec<String> = Vec::new();
58	    let mut injection_alerts: Vec<String> = Vec::new();
59	
60	    for d in distractions {
61	        if matches!(d.suggested_action, ImmuneAction::Block) {
62	            allowed = false;
63	            reasons.push(format!(
64	                "blocked by {} distraction",
65	                distraction_kind_to_str(&d.kind)
66	            ));
67	        }
68	        distraction_alerts.push(format!(
69	            "{} detected (confidence: {:.0}%) — {}",
70	            distraction_kind_to_str(&d.kind),
71	            d.confidence * 100.0,
72	            immune_action_to_str(&d.suggested_action)
73	        ));
74	    }
75	
76	    if injection.score >= 0.7 {
77	        allowed = false;
78	        reasons.push(format!(
79	            "page blocked: injection score {:.0}%",
80	            injection.score * 100.0
81	        ));
82	    } else if injection.score >= 0.3 {
83	        reasons.push(format!(
84	            "content sanitized: injection score {:.0}%",
85	            injection.score * 100.0
86	        ));
87	    }
88	
89	    for flag in &injection.flagged_content {
90	        injection_alerts.push(format!(
91	            "{}: {} (confidence: {:.0}%)",
92	            flag.location.as_str(),
93	            flag.pattern_matched,
94	            flag.confidence * 100.0
95	        ));
96	    }
97	
98	    ans_proto::ans::ActionCheckResponse {
99	        allowed,
100	        reason: reasons.join("; "),
101	        distraction_alerts,
102	        injection_alerts,
103	    }
104	}
105	
106	fn reason_for_result(result: &InjectionScanResult) -> String {
107	    if result.score < 0.3 {
108	        "No injection patterns detected".into()
109	    } else if result.score < 0.7 {
110	        format!(
111	            "{} potentially malicious patterns found — sanitizing",
112	            result.flagged_content.len()
113	        )
114	    } else {
115	        format!(
116	            "{} injection patterns detected with score {:.0}% — blocking",
117	            result.flagged_content.len(),
118	            result.score * 100.0
119	        )
120	    }
121	}
