1	//! Platform-abstracted Arrow IPC via memory-mapped files.
2	//!
3	//! Bulk data (screenshots, large DOM trees) travels via Arrow IPC,
4	//! not gRPC payloads. The gRPC message carries only a shared-memory key;
5	//! the receiver opens the mmap region and reads the Arrow arrays directly.
6	//!
7	//! Platform locations:
8	//! - Linux: `/dev/shm/ans-{key}.arrow`
9	//! - macOS: `$TMPDIR/ans-{key}.arrow`
10	//! - Windows: `%TEMP%/ans-{key}.arrow`
11	
12	use std::fs;
13	use std::path::{Path, PathBuf};
14	
15	use arrow::array::RecordBatch;
16	use arrow::ipc::reader::FileReader;
17	use arrow::ipc::writer::FileWriter;
18	use uuid::Uuid;
19	
20	/// A memory-mapped Arrow IPC buffer identified by a random key.
21	///
22	/// On drop, the backing file is removed from disk.
23	pub struct IpcBuffer {
24	    path: PathBuf,
25	    key: String,
26	}
27	
28	impl IpcBuffer {
29	    /// Create a new IPC buffer with a unique key.
30	    /// The backing file is created in the platform-appropriate shm directory.
31	    pub fn create() -> Result<Self, std::io::Error> {
32	        let key = Uuid::new_v4().to_string();
33	        let filename = format!("ans_{key}.arrow");
34	        let path = shm_dir().join(&filename);
35	        Ok(Self { path, key })
36	    }
37	
38	    /// The unique key identifying this buffer.
39	    /// Pass this to the receiving side via gRPC.
40	    #[must_use] 
41	    pub fn key(&self) -> &str {
42	        &self.key
43	    }
44	
45	    /// The full path to the backing file.
46	    #[must_use] 
47	    pub fn path(&self) -> &Path {
48	        &self.path
49	    }
50	
51	    /// Write a single [`RecordBatch`] to the IPC file.
52	    pub fn write_batch(&self, batch: &RecordBatch) -> Result<(), arrow::error::ArrowError> {
53	        let file = fs::File::create(&self.path)?;
54	        let mut writer = FileWriter::try_new(file, &batch.schema())?;
55	        writer.write(batch)?;
56	        writer.finish()?;
57	        Ok(())
58	    }
59	
60	    /// Read a [`RecordBatch`] from the IPC file.
61	    pub fn read_batch(&self) -> Result<RecordBatch, arrow::error::ArrowError> {
62	        let file = fs::File::open(&self.path)?;
63	        let reader = FileReader::try_new(file, None)?;
64	        reader.into_iter().next().ok_or_else(|| {
65	            arrow::error::ArrowError::IoError(
66	                "IPC file is empty".into(),
67	                std::io::Error::new(std::io::ErrorKind::UnexpectedEof, "empty IPC file"),
68	            )
69	        })?
70	    }
71	}
72	
73	impl Drop for IpcBuffer {
74	    fn drop(&mut self) {
75	        if self.path.exists() {
76	            let _ = fs::remove_file(&self.path);
77	        }
78	    }
79	}
80	
81	/// Return the platform-appropriate shared memory directory.
82	#[must_use] 
83	pub fn shm_dir() -> PathBuf {
84	    if cfg!(target_os = "linux") {
85	        PathBuf::from("/dev/shm")
86	    } else {
87	        std::env::temp_dir()
88	    }
89	}
