1	//! Typed CDP command builders and response parsers.
2	//!
3	//! Each CDP domain (Page, DOM, Runtime, Input) gets a typed command
4	//! builder function that produces the JSON-RPC wire format and parser
5	//! functions that extract typed results from responses.
6	
7	use serde_json::Value as Json;
8	use std::sync::atomic::AtomicI64;
9	
10	// ── Wire types ───────────────────────────────────────────────────────
11	
12	static NEXT_ID: AtomicI64 = AtomicI64::new(1);
13	
14	fn next_id() -> i64 {
15	    NEXT_ID.fetch_add(1, std::sync::atomic::Ordering::SeqCst)
16	}
17	
18	/// A CDP command ready for serialization to JSON-RPC.
19	#[derive(Debug, Clone)]
20	pub struct CdpCommand {
21	    pub id: i64,
22	    pub method: String,
23	    pub params: Json,
24	}
25	
26	impl CdpCommand {
27	    /// Create a new command with an auto-incremented id.
28	    pub fn new(method: impl Into<String>, params: Json) -> Self {
29	        Self {
30	            id: next_id(),
31	            method: method.into(),
32	            params,
33	        }
34	    }
35	
36	    /// Serialize to the JSON-RPC wire format.
37	    #[must_use] 
38	    pub fn to_json(&self) -> String {
39	        serde_json::to_string(&serde_json::json!({
40	            "id": self.id,
41	            "method": self.method,
42	            "params": self.params,
43	        }))
44	        .unwrap_or_default()
45	    }
46	}
47	
48	/// A parsed CDP response.
