384	// ── Simple base64 decoder (no external crate needed) ─────────────────
385	
386	fn base64_decode(input: &str) -> Option<Vec<u8>> {
387	    const CHARS: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
388	    let mut buf = Vec::with_capacity(input.len() * 3 / 4);
389	    let mut accum = 0u32;
390	    let mut bits = 0u32;
391	
392	    for b in input.bytes() {
393	        if b == b'=' {
394	            break;
395	        }
396	        if b.is_ascii_whitespace() {
397	            continue;
398	        }
399	        let idx = CHARS.iter().position(|&c| c == b)? as u32;
400	        accum = (accum << 6) | idx;
401	        bits += 6;
402	        if bits >= 8 {
403	            bits -= 8;
404	            buf.push((accum >> bits) as u8);
405	            accum &= (1 << bits) - 1;
406	        }
407	    }
408	    Some(buf)
409	}
