1	/// Compile ans.proto at build time.
2	fn main() -> Result<(), Box<dyn std::error::Error>> {
3	    // Use vendored protoc so users don't need to install it separately.
4	    let protoc_path = protoc_bin_vendored::protoc_bin_path().map_err(|e| {
5	        Box::<dyn std::error::Error>::from(format!("protoc not found: {e}"))
6	    })?;
7	    std::env::set_var("PROTOC", protoc_path);
8	
9	    tonic_build::configure()
10	        // Suppress clippy in generated code — we can't edit protobuf output.
11	        .type_attribute(
12	            ".",
13	            "#[allow(clippy::all, clippy::pedantic, clippy::nursery, clippy::cargo)]",
14	        )
15	        .build_server(true)
16	        .build_client(true)
17	        .protoc_arg("--experimental_allow_proto3_optional")
18	        .compile_protos(&["../../proto/ans.proto"], &["../../proto"])?;
19	    println!("cargo:rerun-if-changed=../../proto/ans.proto");
20	    Ok(())
21	}
