9	/// Return Chrome CLI flags for a given stealth level.
10	#[must_use]
11	pub fn chrome_flags(level: StealthLevel) -> Vec<String> {
12	    let base = vec![
13	        // ── Critical automation masking ──────────────────────
14	        "--disable-blink-features=AutomationControlled".to_string(),
15	        "--disable-features=ChromeWhatsNewUI,TranslateUI,InterestFeedContentSuggestions,OptimizationHints,MediaRouter,ProcessPerSiteUpToMainFrameThreshold,DialMediaRouteProvider,CalculateNativeWinOcclusion,BlockInsecurePrivateNetworkRequests,InterestFeedContentSuggestions,CertificateTransparencyComponentUpdater,AutofillServerCommunication,PasswordLeakDetection,SafeBrowsingEnhancedProtection,SafeBrowsingUpdate,PrivacySandboxSettings,ChromeWhatsNewUI,DownloadBubble,DownloadBubbleV2,BackForwardCache".to_string(),
16	        // ── Prevent automation flag leaks ────────────────────
17	        "--disable-field-trial-config".to_string(),
18	        "--disable-hang-monitor".to_string(),
19	        "--disable-prompt-on-repost".to_string(),
20	        "--disable-component-update".to_string(),
21	        "--disable-domain-reliability".to_string(),
22	        "--disable-ipc-flooding-protection".to_string(),
23	        "--no-pings".to_string(),
24	        "--no-service-autorun".to_string(),
25	    ];
26	
27	    let mut flags = base;
28	
29	    if level >= StealthLevel::Standard {
30	        flags.extend(vec![
31	            "--disable-web-security".to_string(),
32	            "--disable-features=SignedHTTPExchange,IsolateOrigins,site-per-process".to_string(),
33	            "--enable-features=NetworkService,NetworkServiceInProcess".to_string(),
34	            "--disable-client-side-phishing-detection".to_string(),
35	            "--disable-component-extensions-with-background-pages".to_string(),
36	            "--disable-crash-reporter".to_string(),
