39	        ]);
40	    }
41	
42	    if level >= StealthLevel::Aggressive {
43	        flags.extend(vec![
44	            "--disable-features=VizDisplayCompositor".to_string(),
45	            "--disable-logging".to_string(),
46	            "--disable-background-timer-throttling".to_string(),
47	            "--disable-renderer-backgrounding".to_string(),
48	            "--disable-backgrounding-occluded-windows".to_string(),
49	            "--disable-popup-blocking".to_string(),
50	            "--disable-password-generation".to_string(),
51	            "--disable-save-password-bubble".to_string(),
52	            "--disable-infobars".to_string(),
53	            "--force-color-profile=srgb".to_string(),
54	            // Aggressive: virtual display buffer
55	            "--use-gl=swiftshader".to_string(),
56	            "--use-angle=swiftshader".to_string(),
57	        ]);
58	    }
59	
60	    if level >= StealthLevel::Paranoid {
61	        flags.extend(vec![
62	            "--disable-features=AudioServiceOutOfProcess".to_string(),
63	            "--disable-breakpad".to_string(),
64	            "--disable-crashpad".to_string(),
65	            "--disable-dev-shm-usage".to_string(),
66	            "--disable-gpu-sandbox".to_string(),
67	            "--disable-software-rasterizer".to_string(),
68	            "--enable-webgl".to_string(),
69	            "--enable-gpu-rasterization".to_string(),
70	            "--ignore-gpu-blocklist".to_string(),
71	            "--use-fake-device-for-media-stream".to_string(),
72	            "--use-fake-ui-for-media-stream".to_string(),
73	            "--disable-notifications".to_string(),
74	            "--disable-geolocation".to_string(),
75	            "--disable-reading-from-canvas".to_string(), // anti-canvas-fingerprinting
76	        ]);
77	    }
