1	//! CDP WebSocket client implementing [`ans_core::BrowserBackend`].
2	//!
3	//! Architecture:
4	//! ```text
5	//! CdpBackend
6	//!   ├── ChromiumProcess (owns child process)
7	//!   └── CdpConnection
8	//!         ├── write_tx: mpsc::Sender<String>  (outgoing commands)
9	//!         ├── pending: Arc<Mutex<HashMap<id, oneshot::Sender>>>
10	//!         └── reader task (spawned, reads WS messages)
11	//! ```
12	
13	use std::collections::HashMap;
14	use std::sync::Arc;
15	use std::time::Duration;
16	
17	use ans_core::backend::{BrowserError, ImageFormat, PageState};
18	use ans_core::distill::{DistillMode, DistilledPage};
19	use ans_core::session::ActionOutcome;
20	use ans_stealth::StealthConfig;
21	use async_trait::async_trait;
22	use futures_util::{SinkExt, StreamExt};
23	use tokio::sync::{mpsc, oneshot, Mutex};
24	use tokio_tungstenite::tungstenite::Message;
25	use tracing;
26	
27	use crate::command::{self, CdpCommand, CdpError, CdpMessage};
28	use crate::process::ChromiumProcess;
29	
30	// ── CdpConnection ────────────────────────────────────────────────────
31	
32	type PendingMap = Arc<Mutex<HashMap<i64, oneshot::Sender<Result<serde_json::Value, CdpError>>>>>;
33	
34	struct CdpConnection {
35	    write_tx: mpsc::Sender<String>,
36	    pending: PendingMap,
37	}
38	
39	impl CdpConnection {
40	    /// Establish a WebSocket connection and spawn the reader task.
41	    async fn connect(debug_url: &str) -> Result<Self, BrowserError> {
42	        let (ws, _) = tokio_tungstenite::connect_async(debug_url)
43	            .await
44	            .map_err(|e| BrowserError::ConnectionLost(e.to_string()))?;
45	
46	        let (mut write, read) = ws.split();
47	        let (write_tx, mut write_rx) = mpsc::channel::<String>(256);
48	        let pending: PendingMap = Arc::new(Mutex::new(HashMap::new()));
49	
50	        // Writer task: pumps messages from the mpsc channel to the WebSocket
51	        let writer_pending = pending.clone();
52	        tokio::spawn(async move {
53	            while let Some(msg) = write_rx.recv().await {
54	                if let Err(e) = write.send(Message::Text(msg)).await {
55	                    let _ = writer_pending.lock().await;
56	                    tracing::error!(?e, "CDP write failed");
57	                    break;
58	                }
59	            }
60	        });
61	
62	        // Reader task: reads WebSocket messages, dispatches responses to pending
63	        // commands, and forwards events to the broadcast channel
64	        let reader_pending = pending.clone();
65	        tokio::spawn(async move {
66	            let mut read = read;
67	            while let Some(msg) = read.next().await {
68	                match msg {
69	                    Ok(Message::Text(text)) => {
70	                        let text_str = text.clone();
71	                        if let Some(cdp_msg) = command::parse_message(&text_str) {
72	                            match cdp_msg {
73	                                CdpMessage::Response(resp) => {
74	                                    let id = resp.id;
75	                                    let result = resp.into_result();
76	                                    let mut map = reader_pending.lock().await;
77	                                    if let Some(tx) = map.remove(&id) {
78	                                        let _ = tx.send(result);
79	                                    }
80	                                }
81	                                CdpMessage::Event(event) => {
82	                                    tracing::trace!(
83	                                        method = %event.method,
84	                                        "CDP event"
85	                                    );
86	                                }
87	                            }
88	                        }
89	                    }
90	                    Err(e) => {
91	                        tracing::error!(?e, "CDP WebSocket read error");
92	                        break;
93	                    }
94	                    _ => {}
95	                }
96	            }
97	            tracing::debug!("CDP reader task exiting");
98	        });
99	
100	        Ok(Self { write_tx, pending })
101	    }
102	
103	    /// Send a CDP command and await its response with a timeout.
104	    async fn send_command(
105	        &self,
106	        cmd: CdpCommand,
107	        timeout: Duration,
108	    ) -> Result<serde_json::Value, BrowserError> {
109	        let (tx, rx) = oneshot::channel();
110	        let id = cmd.id;
111	
112	        self.pending.lock().await.insert(id, tx);
113	        let json = cmd.to_json();
114	
115	        self.write_tx
116	            .send(json)
117	            .await
118	            .map_err(|e| BrowserError::ConnectionLost(e.to_string()))?;
119	
120	        tokio::time::timeout(timeout, rx)
121	            .await
122	            .map_err(|_| BrowserError::NavigationTimeout(timeout))?
123	            .map_err(|_| BrowserError::ConnectionLost("sender dropped".into()))?
124	            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))
125	    }
126	}
