128	// ── CdpBackend ───────────────────────────────────────────────────────
129	
130	/// CDP-backed browser implementation.
131	///
132	/// Owns the Chromium child process and the WebSocket connection.
133	pub struct CdpBackend {
134	    // Held for RAII cleanup: Chromium is killed on Drop.
135	    _process: ChromiumProcess,
136	    connection: CdpConnection,
137	    // Current page state, updated after navigations.
138	    current_url: Mutex<String>,
139	    /// Stealth configuration (anti-detection engine).
140	    /// Stored for use in mouse/keyboard humanization.
141	    stealth: Option<StealthConfig>,
142	}
143	
144	impl CdpBackend {
145	    /// Launch a new Chromium instance and establish a CDP connection.
146	    ///
147	    /// When `stealth` is provided, anti-detection scripts are injected
148	    /// via `Page.addScriptToEvaluateOnNewDocument` before any page loads.
149	    pub async fn launch(stealth: Option<StealthConfig>) -> Result<Self, BrowserError> {
150	        let process = ChromiumProcess::launch(stealth.as_ref())
151	            .await
152	            .map_err(|e| BrowserError::Internal(e.into()))?;
153	
154	        // Connect to the page-level WebSocket URL (not browser-level).
155	        // Page.*, DOM.*, and Runtime.* commands require a page target connection.
156	        let page_url = process.page_url().to_string();
157	        let connection = CdpConnection::connect(&page_url).await?;
158	
159	        // Enable domains we need
160	        connection
161	            .send_command(command::page_enable(), Duration::from_secs(10))
162	            .await?;
163	        connection
164	            .send_command(command::dom_enable(), Duration::from_secs(10))
165	            .await?;
166	        connection
167	            .send_command(command::runtime_enable(), Duration::from_secs(10))
168	            .await?;
169	
170	        // Inject anti-detection scripts before any page loads
171	        if let Some(ref config) = stealth {
172	            let scripts = config.init_scripts();
173	            if !scripts.is_empty() {
174	                tracing::info!(
175	                    count = scripts.len(),
176	                    level = ?config.level,
177	                    "Injecting stealth scripts"
178	                );
179	                for script in &scripts {
180	                    let cmd = command::page_add_script_to_evaluate_on_new_document(script);
181	                    if let Err(e) = connection
182	                        .send_command(cmd, Duration::from_secs(10))
183	                        .await
184	                    {
185	                        tracing::warn!(?e, "Failed to inject stealth script");
186	                    }
187	                }
188	            }
189	        }
190	
191	        tracing::info!("CDP backend ready");
192	
193	        Ok(Self {
194	            _process: process,
195	            connection,
196	            current_url: Mutex::new(String::new()),
197	            stealth,
198	        })
199	    }
200	
201	    /// Send a command and drop the response (fire-and-forget).
202	    async fn send_ignore(&self, cmd: CdpCommand) {
203	        let json = cmd.to_json();
204	        let _ = self.connection.write_tx.send(json).await;
205	    }
206	}
