331	    async fn click(&self, selector: &str) -> Result<ActionOutcome, BrowserError> {
332	        let start = std::time::Instant::now();
333	
334	        // 1. Get document root
335	        let doc_result = self
336	            .connection
337	            .send_command(command::dom_get_document(0), Duration::from_secs(5))
338	            .await?;
339	        let root_id = command::parse_dom_node_id(&doc_result)
340	            .map_err(|e| BrowserError::CdpProtocol(e.to_string()))?;
341	
342	        // 2. Query selector
343	        let qs_result = self
344	            .connection
345	            .send_command(
346	                command::dom_query_selector(root_id, selector),
347	                Duration::from_secs(5),
348	            )
349	            .await
350	            .map_err(|e| {
351	                if matches!(e, BrowserError::CdpProtocol(_)) {
352	                    BrowserError::SelectorNotFound(selector.to_string())
353	                } else {
354	                    e
355	                }
356	            })?;
357	
358	        let node_id = command::parse_query_selector_result(&qs_result)
359	            .map_err(|_| BrowserError::SelectorNotFound(selector.to_string()))?;
360	
361	        // 3. Get box model for coordinates
362	        let box_result = self
363	            .connection
364	            .send_command(command::dom_get_box_model(node_id), Duration::from_secs(5))
365	            .await?;
366	        let box_model = command::parse_box_model(&box_result)
367	            .map_err(|_| BrowserError::NotInteractable(selector.to_string()))?;
368	
369	        let mut center_x = box_model.x + box_model.width / 2.0;
370	        let mut center_y = box_model.y + box_model.height / 2.0;
371	
372	        // Humanized: slight random offset from exact center + pre-click delay
373	        let humanize = self.stealth.as_ref().is_some_and(|s| s.humanize);
374	        if humanize {
375	            use ans_stealth::humanize;
376	            center_x += ans_stealth::humanize::position_jitter();
377	            center_y += ans_stealth::humanize::position_jitter();
378	            tokio::time::sleep(humanize::click_linger()).await;
379	        }
380	
381	        // 4. Scroll element into view
382	        let _ = self
383	            .connection
384	            .send_command(
385	                command::dom_scroll_into_view(node_id),
386	                Duration::from_secs(5),
387	            )
388	            .await;
389	
390	        // Brief delay for scroll animation
391	        tokio::time::sleep(Duration::from_millis(100)).await;
392	
393	        // 5. Dispatch mouse events
394	        if humanize {
395	            // Seek to element with movement, then press/release
396	            self.send_ignore(command::input_dispatch_mouse_event(
397	                "mouseMoved",
398	                center_x,
399	                center_y,
400	                "none",
401	            ))
402	            .await;
403	            tokio::time::sleep(Duration::from_millis(20)).await;
404	        }
405	
406	        self.send_ignore(command::input_dispatch_mouse_event(
407	            "mousePressed",
408	            center_x,
409	            center_y,
410	            "left",
411	        ))
412	        .await;
413	        tokio::time::sleep(Duration::from_millis(
414	            if humanize { 60 } else { 50 },
415	        ))
416	        .await;
417	        self.send_ignore(command::input_dispatch_mouse_event(
418	            "mouseReleased",
419	            center_x,
420	            center_y,
421	            "left",
422	        ))
423	        .await;
424	
425	        let elapsed = start.elapsed();
426	
427	        Ok(ActionOutcome {
428	            success: true,
429	            error_message: None,
430	            execution_time_ms: elapsed.as_millis() as u64,
431	            page_url_after: Some(self.current_url.lock().await.clone()),
432	            dom_changed: true,
433	        })
434	    }
