601	/// Escape a string for safe embedding in a JavaScript string literal.
602	fn escape_js_string(s: &str) -> String {
603	    s.replace('\\', "\\\\")
604	        .replace('\'', "\\'")
605	        .replace('\n', "\\n")
606	        .replace('\r', "\\r")
