1	//! Semantic block segmentation.
2	//!
3	//! Groups distilled elements into semantic regions: navigation,
4	//! main content, forms, sidebars, footers, ads, cookie banners.
5	//! Uses heuristics (position, tag, role, ARIA landmarks) — no ML in v1.
6	
7	use ans_core::distill::{BlockType, DistilledElement, SemanticBlock};
8	
9	/// Heuristic pattern matchers for common DOM landmarks.
10	const NAV_TAGS: &[&str] = &["nav", "header"];
11	const MAIN_TAGS: &[&str] = &["main", "article", "section"];
12	const FORM_TAGS: &[&str] = &["form"];
13	const SIDEBAR_TAGS: &[&str] = &["aside"];
14	const FOOTER_TAGS: &[&str] = &["footer"];
15	
16	const AD_CLASS_PATTERNS: &[&str] = &[
17	    "ad",
18	    "advertisement",
19	    "sponsor",
20	    "banner-ad",
21	    "display-ad",
22	    "google-ad",
23	    "dfp-ad",
24	    "ad-container",
25	    "promoted",
26	];
27	const COOKIE_PATTERNS: &[&str] = &[
28	    "cookie",
29	    "gdpr",
30	    "consent",
31	    "privacy-policy",
32	    "cookie-banner",
33	    "cookie-notice",
34	];
35	const POPUP_PATTERNS: &[&str] = &["popup", "modal", "overlay", "dialog", "lightbox"];
36	
37	/// Classify a single element into a block type using tag, role, text, and context.
38	#[must_use] 
39	pub fn classify_element(
40	    tag: &str,
41	    role: Option<&str>,
42	    text: &str,
43	    class_id_hint: &str,
44	) -> BlockType {
45	    let tag_lower = tag.to_lowercase();
46	    let hint_lower = class_id_hint.to_lowercase();
47	    let text_lower = text.to_lowercase();
48	    let combined = format!("{} {} {}", hint_lower, text_lower, role.unwrap_or(""));
49	
50	    // ARIA roles are highest-signal — check first
51	    if let Some(r) = role {
52	        match r {
53	            "navigation" | "banner" => return BlockType::Navigation,
54	            "main" => return BlockType::MainContent,
55	            "form" | "search" => return BlockType::Form,
56	            "complementary" => return BlockType::Sidebar,
57	            "contentinfo" => return BlockType::Footer,
58	            "dialog" | "alertdialog" => return BlockType::Popup,
59	            _ => {}
60	        }
61	    }
62	
63	    // Tag-level classification
64	    if NAV_TAGS.contains(&tag_lower.as_str()) {
65	        return BlockType::Navigation;
66	    }
67	    if MAIN_TAGS.contains(&tag_lower.as_str()) {
68	        return BlockType::MainContent;
69	    }
70	    if FORM_TAGS.contains(&tag_lower.as_str()) {
71	        return BlockType::Form;
72	    }
73	    if SIDEBAR_TAGS.contains(&tag_lower.as_str()) {
74	        return BlockType::Sidebar;
75	    }
76	    if FOOTER_TAGS.contains(&tag_lower.as_str()) {
77	        return BlockType::Footer;
78	    }
79	
80	    // Distraction detection via class/id/text patterns
81	    for pat in COOKIE_PATTERNS {
82	        if combined.contains(pat) {
83	            return BlockType::CookieBanner;
84	        }
85	    }
86	    for pat in POPUP_PATTERNS {
87	        if hint_lower.contains(pat) {
88	            return BlockType::Popup;
89	        }
90	    }
91	    for pat in AD_CLASS_PATTERNS {
92	        if hint_lower.contains(pat) {
93	            return BlockType::Ad;
94	        }
95	    }
96	
97	    // Heuristic: dense links cluster → likely navigation
98	    if tag_lower == "div" || tag_lower == "ul" {
99	        let link_count = text_lower.matches("href").count();
100	        if link_count >= 3 {
101	            return BlockType::Navigation;
102	        }
103	    }
104	
105	    BlockType::Unknown
106	}
107	
108	/// Segment a flat list of elements into semantic blocks.
109	///
110	/// Groups consecutive elements that share a semantic region.
111	/// Elements that can't be classified are attached to the nearest
112	/// classified ancestor or grouped as Unknown.
113	#[must_use] 
114	pub fn segment_blocks(elements: &[DistilledElement]) -> Vec<SemanticBlock> {
115	    if elements.is_empty() {
116	        return vec![];
117	    }
118	
119	    let mut blocks: Vec<SemanticBlock> = Vec::new();
120	    let mut current_type = BlockType::Unknown;
121	    let mut current_text = String::new();
122	    let mut current_indices: Vec<usize> = Vec::new();
123	
124	    for (i, el) in elements.iter().enumerate() {
125	        let role = el.role.as_deref();
126	        let raw_attrs: String = el
127	            .attributes
128	            .iter()
129	            .fold(String::new(), |mut acc, (k, v)| {
130	                use std::fmt::Write;
131	                let _ = write!(acc, "{k}={v} ");
132	                acc
133	            });
134	        let class_id_hint = format!(
135	            "{} {} {}",
136	            el.attributes.get("class").map_or("", std::string::String::as_str),
137	            el.attributes.get("id").map_or("", std::string::String::as_str),
138	            raw_attrs
139	        );
140	
141	        let block_type = classify_element(&el.tag, role, &el.text, &class_id_hint);
142	
143	        if block_type == current_type {
144	            // Extend current block
145	            current_text.push(' ');
146	            current_text.push_str(&el.text);
147	            current_indices.push(i);
148	        } else {
149	            // Flush previous block
150	            if !current_indices.is_empty() {
151	                blocks.push(SemanticBlock {
152	                    block_type: current_type.clone(),
153	                    text_content: current_text.trim().to_string(),
154	                    element_indices: current_indices.clone(),
155	                    goal_relevance_score: default_relevance(&current_type),
156	                });
157	            }
158	            current_type = block_type;
159	            current_text.clone_from(&el.text);
160	            current_indices = vec![i];
161	        }
162	    }
163	
164	    // Flush final block
165	    if !current_indices.is_empty() {
166	        let relevance = default_relevance(&current_type);
167	        blocks.push(SemanticBlock {
168	            block_type: current_type,
169	            text_content: current_text.trim().to_string(),
170	            element_indices: current_indices,
171	            goal_relevance_score: relevance,
172	        });
173	    }
174	
175	    blocks
176	}
177	
178	const fn default_relevance(block_type: &BlockType) -> f32 {
179	    match block_type {
180	        BlockType::MainContent => 1.0,
181	        BlockType::Form => 0.9,
182	        BlockType::Navigation => 0.5,
183	        BlockType::Sidebar | BlockType::Unknown => 0.3,
184	        BlockType::Footer => 0.2,
185	        BlockType::Ad | BlockType::CookieBanner => 0.0,
186	        BlockType::Popup => 0.1,
187	    }
188	}
