1	//! CDP-level evasion scripts.
2	//!
3	//! JavaScript patches injected via `Page.addScriptToEvaluateOnNewDocument`
4	//! before ANY page script executes. Each patch targets a specific
5	//! browser automation detection vector.
6	//!
7	//! Patches are organized by detection vector and bundled into levels.
8	//! The self-audit script verifies all patches are active.
9	
10	use super::{FingerprintProfile, StealthLevel};
11	
12	/// Return the complete set of init scripts for a stealth level.
13	#[must_use]
14	pub fn init_scripts(level: StealthLevel, profile: &FingerprintProfile) -> Vec<String> {
15	    if level == StealthLevel::Off {
16	        return vec![];
17	    }
18	
19	    let mut scripts = vec![
20	        // Core evasions — applied at all levels
21	        patch_navigator_webdriver(),
22	        patch_chrome_runtime(),
23	        patch_navigator_plugins(),
24	        patch_navigator_languages(),
25	        patch_window_dimensions(),
26	        patch_hardware_concurrency(),
27	        patch_device_memory(),
28	        patch_notification_permission(),
29	    ];
30	
31	    if level >= StealthLevel::Standard {
32	        scripts.extend(vec![
33	            patch_permissions_query(),
34	            patch_webgl_vendor(profile),
35	            patch_media_devices(),
36	            patch_timezone_offset(),
37	            patch_intl_datetime_format(),
38	        ]);
39	    }
40	
41	    if level >= StealthLevel::Aggressive {
42	        scripts.extend(vec![
43	            patch_canvas_fingerprint(),
44	            patch_audio_fingerprint(),
45	            patch_font_enumeration(),
46	            patch_screen_resolution(profile),
47	            patch_battery_api(),
48	            patch_connection_type(),
49	        ]);
50	    }
51	
52	    if level >= StealthLevel::Paranoid {
53	        scripts.extend(vec![
54	            patch_error_stack_trace(),
55	            patch_performance_timing(),
56	            patch_navigator_platform(profile),
57	            patch_webdriver_sensors(),
58	            patch_virtual_keyboard(),
59	            patch_installed_app_get(),
60	        ]);
61	    }
62	
63	    scripts
64	}
