342	(function() {{
343	    var vendorStr = '{vendor}';
344	    var rendererStr = '{renderer}';
345	    var getParam = WebGLRenderingContext.prototype.getParameter;
346	    if (!getParam) return;
347	    WebGLRenderingContext.prototype.getParameter = function(p) {{
348	        if (p === 37445) return vendorStr;
349	        if (p === 37446) return rendererStr;
350	        return getParam.call(this, p);
351	    }};
352	    var getParam2 = WebGL2RenderingContext && WebGL2RenderingContext.prototype.getParameter;
353	    if (getParam2) {{
354	        WebGL2RenderingContext.prototype.getParameter = function(p) {{
355	            if (p === 37445) return vendorStr;
356	            if (p === 37446) return rendererStr;
357	            return getParam2.call(this, p);
358	        }};
359	    }}
360	    // Also patch getExtension to return null for DEBUG_RENDERER_INFO
361	    var origGetExt = WebGLRenderingContext.prototype.getExtension;
362	    WebGLRenderingContext.prototype.getExtension = function(name) {{
363	        if (name === 'WEBGL_debug_renderer_info') return null;
364	        return origGetExt.call(this, name);
365	    }};
366	    if (WebGL2RenderingContext) {{
367	        var origGetExt2 = WebGL2RenderingContext.prototype.getExtension;
368	        WebGL2RenderingContext.prototype.getExtension = function(name) {{
369	            if (name === 'WEBGL_debug_renderer_info') return null;
370	            return origGetExt2.call(this, name);
371	        }};
372	    }}
373	}})();
374	"#
375	    )
376	}
